INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-21', E'약자를 위한 배려 (누가복음 18장)', E'누가복음 18장', E'예수님께서는 예루살렘으로 향하는 길에서 제자들과 무리들에게 하나님 나라의 본질을 가르치셨습니다. 누가복음 18장은 기도와 겸손, 그리고 참된 믿음이 무엇인지를 보여주는 귀한 가르침들로 가득합니다.\n\n먼저 예수님은 불의한 재판관과 과부의 비유를 통해 낙심하지 않고 항상 기도해야 함을 가르치십니다. 하나님을 두려워하지 않고 사람을 무시하는 재판관조차 끈질긴 간구에는 응답했는데, 하물며 사랑의 하나님께서 당신의 백성들의 간절한 기도를 외면하시겠느냐는 것입니다. 이어지는 바리새인과 세리의 기도 비유는 하나님께서 받으시는 기도가 어떤 것인지 명확히 보여줍니다. 자신의 의로움을 자랑하며 다른 이를 멸시하는 바리새인의 기도와 달리, "하나님이여 불쌍히 여기소서 나는 죄인이로소이다"(눅 18:13)라는 세리의 겸손한 고백이 하나님께 의롭다 함을 받았습니다.\n\n예수님은 어린아이들을 축복하시며 하나님 나라는 이런 자의 것이라 선언하십니다. 제자들이 어린아이들을 꾸짖었지만, 예수님은 오히려 그들을 가까이 부르셨습니다. 이는 하나님 나라가 지위나 능력이 아닌 순전한 믿음과 겸손함으로 받아들이는 자들의 것임을 보여줍니다. \n\n부유한 관리와의 만남은 영생을 얻는 길이 단순히 계명을 지키는 것을 넘어 예수님을 온전히 따르는 것임을 드러냅니다. 어려서부터 계명을 다 지켰다는 그에게 예수님은 모든 것을 팔아 가난한 자들에게 나누어주고 당신을 따르라 하셨지만, 큰 부자였던 그는 근심하며 떠났습니다. 이는 재물이 하나님보다 우선순위가 될 때 영생의 길을 가로막는 장애물이 됨을 보여줍니다.\n\n마지막으로 여리고 성 밖의 맹인은 예수님을 "다윗의 자손"으로 부르며 간절히 도움을 청했습니다. 사람들의 제지에도 불구하고 더욱 크게 부르짖는 그의 믿음을 보시고, 예수님은 "네 믿음이 너를 구원하였느니라"고 선언하시며 그의 눈을 뜨게 하셨습니다. 이처럼 누가복음 18장은 하나님께서 기뻐하시는 것이 교만한 자의 업적이 아니라 겸손한 자의 믿음임을 분명히 보여줍니다.', E'오늘의 핵심\n하나님께서는 자신의 의로움을 내세우는 교만한 마음이 아니라, 전적으로 하나님의 은혜를 구하는 겸손하고 간절한 믿음을 기뻐하십니다.\n\n묵상 질문\n1. 나의 기도가 하나님께 간구하는 것보다 나의 의로움을 드러내는 데 치중하고 있지는 않은가요?\n2. 어린아이처럼 순전한 마음으로 하나님 나라를 받아들이는 것을 방해하는 것은 무엇일까요?\n3. 여리고의 맹인처럼 절박한 마음으로 예수님을 부르짖어 본 적이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-22', E'약자를 위한 배려 (누가복음 19장)', E'누가복음 19장', E'여리고 성으로 들어가시는 예수님 앞에는 한 작은 남자가 있었습니다. 삭개오는 로마 제국을 위해 일하는 세리장으로서 경제적으로는 부유했지만, 동족들로부터는 철저히 배척당하는 외로운 사람이었습니다. 그런 그가 예수님에 대한 소문을 듣고 그분이 어떤 분인지 보고자 하는 마음으로 돌무화과나무에 올라갔다는 것은, 단순한 호기심을 넘어선 영적 갈망의 표현이었습니다.\n\n예수님께서는 나무 위의 삭개오를 보시고 "삭개오야 속히 내려오라 내가 오늘 네 집에 유하여야 하겠다"(눅 19:5)고 말씀하십니다. 주변 사람들이 죄인의 집에 들어간다며 수군거렸지만, 예수님의 관심은 오직 잃어버린 한 영혼을 구원하시는 데 있었습니다. 주님의 사랑을 경험한 삭개오는 즉시 자신의 재산 절반을 가난한 자들에게 나누고 부당하게 취한 것은 네 배로 갚겠다고 선언합니다. 이것이 바로 구원받은 자의 변화된 삶의 모습입니다.\n\n이어지는 므나 비유는 주님께서 맡기신 것을 어떻게 관리해야 하는지를 가르쳐줍니다. 충성된 종들은 맡은 것을 잘 활용하여 열매를 맺었지만, 한 종은 주인을 오해하고 두려워하여 아무것도 하지 않았습니다. 하나님의 은혜는 우리가 감사함으로 응답하고 충성스럽게 사용할 때 더욱 풍성해집니다.\n\n예루살렘에 입성하시는 예수님의 모습은 겸손한 왕의 모습으로 나타납니다. 제자들과 무리가 환호했지만, 예수님께서는 도리어 예루살렘을 보시며 우셨습니다. 구원의 때를 알지 못하는 백성들을 향한 주님의 애통함이 드러나는 장면입니다. 성전에서 장사하는 자들을 내쫓으시며 "내 집은 기도하는 집"이라고 선포하신 것은, 종교가 형식과 이익추구로 변질되었을 때 하나님께서 얼마나 슬퍼하시는지를 보여줍니다.', E'오늘의 핵심\n예수님께서는 세상에서 소외된 삭개오를 찾아 구원하시고, 예루살렘을 향해 우시며, 기도의 집이 되어야 할 성전을 정화하심으로써 잃어버린 영혼과 잃어버린 예배를 회복시키십니다.\n\n묵상 질문\n1. 나는 삭개오처럼 예수님을 간절히 만나고자 하는 영적 갈망을 가지고 있나요?\n2. 주님께서 내게 맡기신 은사와 사명을 충성스럽게 사용하고 있나요?\n3. 내 삶과 예배가 진정한 기도와 헌신으로 채워져 있나요, 아니면 형식과 이익추구로 변질되어 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-23', E'약자를 위한 배려 (누가복음 20장)', E'누가복음 20장', E'예루살렘에 입성하신 예수님께서는 성전에서 백성들을 가르치며 복음을 전하셨습니다. 그러자 종교 지도자들이 몰려와 예수님의 권위에 대해 따져 묻습니다. 예수님께서는 요한의 세례가 어디로부터 왔는지 되물으심으로써 그들의 위선을 드러내셨습니다. 진리보다는 자신들의 체면과 안위만을 생각하는 그들의 모습이 여실히 나타납니다.\n\n이어서 예수님께서는 악한 농부들의 비유를 통해 하나님의 마음을 보여주십니다. 포도원 주인이 보낸 종들을 때리고 능욕하며, 마침내 사랑하는 아들마저 죽이는 농부들의 모습은 선지자들과 하나님의 아들을 거부하는 이스라엘의 역사를 압축적으로 보여줍니다. "건축자들의 버린 돌이 모퉁이의 머릿돌이 되었느니라"(눅 20:17)는 말씀은 십자가에서 버림받으실 예수님께서 결국 구원의 기초가 되실 것을 예언하고 있습니다.\n\n종교 지도자들은 예수님을 함정에 빠뜨리려고 가이사에게 세금을 바치는 문제로 시험합니다. 그러나 예수님께서는 "가이사의 것은 가이사에게, 하나님의 것은 하나님께 바치라"는 지혜로운 답변으로 그들을 침묵시키셨습니다. 이는 단순히 정치적 문제를 회피하신 것이 아니라, 우리가 하나님의 형상으로 지음받은 존재로서 온전히 하나님께 속해야 함을 가르치신 것입니다.\n\n부활을 부인하는 사두개인들의 질문에 예수님께서는 하나님이 "죽은 자의 하나님이 아니요 살아 있는 자의 하나님"이심을 선포하십니다. 아브라함과 이삭과 야곱이 여전히 하나님 앞에 살아 있다는 이 말씀은 영원한 생명에 대한 확실한 소망을 우리에게 심어줍니다. 예수님께서는 종교적 권위를 내세우며 교만하게 행동하는 서기관들을 경계하시며, 진정한 신앙은 겸손과 섬김에 있음을 가르치셨습니다.', E'오늘의 핵심\n예수님께서는 종교 지도자들의 도전 앞에서 하나님의 권위와 진리를 선포하시며, 참된 신앙은 하나님과 이웃을 향한 겸손한 섬김에 있음을 가르치십니다.\n\n묵상 질문\n1. 나는 하나님의 진리보다 사람들의 시선과 체면을 더 의식하며 살고 있지는 않나요?\n2. 하나님의 형상으로 지음받은 나 자신을 온전히 하나님께 드리고 있나요?\n3. 부활의 소망을 품고 영원한 생명의 관점에서 오늘을 살아가고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-24', E'최후의 만찬', E'누가복음 22장', E'누가복음 22장은 유월절 만찬부터 겟세마네 기도, 그리고 예수님의 체포까지 긴박하게 이어지는 장면을 담고 있습니다. 이 한 장 안에 예수님의 사랑, 제자들의 연약함, 그리고 십자가를 향한 결단이 모두 녹아 있습니다.\n\n예수님께서는 "내가 고난을 받기 전에 너희와 함께 이 유월절 먹기를 원하고 원하였노라"(15절)고 말씀하십니다. ''원하고 원하였노라''는 표현에서 예수님의 깊은 갈망이 느껴집니다. 1400년 역사를 가진 유월절이 이 자리에서 마지막 유월절이자 첫 번째 성찬식으로 전환되는 순간이었습니다. "이것은 너희를 위하여 주는 내 몸이라"(19절), "이 잔은 내 피로 세우는 새 언약이니"(20절). 예수님은 자신의 몸과 피로 새 언약을 여시면서도, 제자들과 함께하는 그 식탁의 시간을 간절히 원하셨습니다.\n\n그런데 같은 식탁에서 제자들은 ''누가 크냐'' 다투고 있었습니다(24절). 예수님은 이 모습 앞에서 화를 내시기보다 "나는 섬기는 자로 너희 중에 있노라"(27절)고 말씀하시며 참된 리더십의 본을 보이십니다. 이어 겟세마네에서는 땀이 핏방울처럼 떨어질 만큼 간절히 기도하시면서도 "내 원대로 마시옵고 아버지의 원대로 되기를 원하나이다"(42절)라고 고백하십니다. 가장 고통스러운 순간에도 아버지의 뜻에 자신을 내어드리신 것입니다.\n\n우리의 일상에도 나의 뜻과 하나님의 뜻 사이에서 갈등하는 순간이 있습니다. 진로 앞에서, 관계의 어려움 속에서, 직장에서의 부당한 상황 앞에서 ''내 원대로''를 내려놓기란 쉽지 않습니다. 하지만 예수님은 그 고통의 한가운데서 기도로 아버지께 나아가셨고, 묵묵히 십자가의 길을 걸어가셨습니다. 오늘 나는 어떤 ''잔'' 앞에 서 있습니까? 그 자리에서 먼저 무릎 꿇고 아버지의 뜻을 구하는 하루가 되기를 소망합니다.', E'오늘의 핵심\n예수님은 장차 다가올 고난을 앞두고 제자들과 마지막 만찬을 나누시며, 인내하고 견디어 마침내 승리할 것을 부탁하셨습니다.\n\n묵상 질문\n1. 예수님이 죽음을 알면서도 제자들과 식사하신 이유가 무엇일까요?\n2. 나는 예수님의 사랑 앞에서 어떻게 응답하고 싶은가요?\n3. 이 최후의 만찬이 내 신앙 안에 어떤 의미로 살아나길 원하시나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-25', E'들러리의 기쁨', E'요한복음 3장', E'예수님께서 오시기 전 예수님의 오실 길을 준비한 이가 바로 세례 요한입니다. 세례 요한은 말라기 선지자 이후 4백여 년간 이어졌던 침묵을 깨고 등장한 사람입니다. 그는 회개하라는 메시지를 선포합니다. 예수님께서는 세례 요한에게 세례를 받으시고, 40일간 광야에서 금식기도를 마치신 후, 마귀의 시험을 물리치셨습니다. 그리고 공생애를 시작하셨습니다. 그 후 세례 요한은 헤롯에 의해 죽임을 당하고 맙니다. 예수의 길을 예비하며 들러리의 기쁨을 누리며 살았던 세례 요한은 짧지만 소중한 사역을 감당하고 죽은 것입니다.\n세례 요한이 죽고 난 후, 예수님께서는 제자들과 함께 갈릴리 가나의 혼인식에 참석하십니다. 이때 예수님께서는 물이 변하여 포도주가 되게 하는 기적을 베푸십니다. 이 기적은 예수님께서 베푸신 첫 표적이었습니다. 유월절이 가깝자 예수님께서는 예루살렘을 방문하셔서 성전을 찾으십니다. 예수님께서는 그곳에서 장사하는 사람들을 내쫓으시고, 성전을 정결하게 하십니다. 유대인들이 "네가 이런 일을 행하니 무슨 표적을 우리에게 보이겠느냐"(요 2:18)라고 시비합니다. 이에 예수님께서는 헐린 성전을 사흘 만에 일으키리라는 말씀으로, 장차 있을 일을 말씀하십니다.', E'오늘의 핵심\n인생들의 빛이 되시는 예수님이 이 땅에 오셔서 인류 구원의 사역을 시작하시고, 세례 요한은 그분의 오실 길을 기쁨으로 준비합니다.\n\n묵상 질문\n1. 주님의 길을 예비하는 일에서 기쁨을 느꼈던 세례 요한을 보며, 하나님은 어떤 마음으로 우리를 사용하고 싶으신 걸까요?\n2. 내 삶에서 남들에게 주목받지 않아도 기꺼이 감당할 수 있는 사역이 있나요?\n3. 세례 요한처럼 주님을 높이고 준비하는 역할에 진심으로 기쁨을 느낄 수 있도록 기도해 보겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-26', E'영원한 생명수이신 예수 (요한복음 4장)', E'요한복음 4장', E'예수님은 유대인이라면 피해 갔을 사마리아 땅을 "통과하여야 하겠는지라"고 말씀하십니다. 이것은 단순한 지리적 경로가 아닌, 한 영혼을 향한 하나님의 구원 계획이었습니다. 정오의 뜨거운 햇볕 아래 홀로 물을 길으러 온 여인, 사람들의 시선을 피해야 했던 그녀에게 예수님은 먼저 다가가십니다. "물을 좀 달라." 모든 것을 주실 수 있는 분이 오히려 목마른 나그네가 되어 구하시는 이 장면은 놀라운 은혜의 시작입니다.\n\n여인은 유대인과 사마리아인 사이의 민족적 장벽을 먼저 언급하지만, 예수님은 전혀 다른 차원의 대화로 이끄십니다. "내가 주는 물을 마시는 자는 영원히 목마르지 아니하리니"(요 4:14). 야곱의 우물에서 나오는 물과는 비교할 수 없는 생명의 물, 그것은 인간의 가장 깊은 갈증을 해결하는 영원한 샘물입니다. 예수님은 여인의 삶의 아픔 - 다섯 번의 결혼 실패와 현재의 불안정한 관계까지 모두 아시면서도, 정죄하지 않으시고 오히려 참된 예배자의 길로 인도하십니다.\n\n가장 인상적인 전환은 여인이 물동이를 버려두고 동네로 달려간 장면입니다. 매일 필요했던 물동이보다 더 중요한 것을 발견한 것입니다. "내가 행한 모든 일을 내게 말한 사람을 와서 보라"는 그녀의 외침은 수치와 소외의 삶에서 벗어난 해방의 선언이었습니다. 한 여인의 변화는 온 마을의 구원으로 이어집니다. 사마리아인들이 예수님을 "참으로 세상의 구주"로 고백하게 된 것입니다.\n\n같은 장에서 왕의 신하가 보여준 믿음도 주목할 만합니다. 죽어가는 아들을 위해 애타게 구했던 그는 예수님의 "네 아들이 살아 있다"는 말씀만을 믿고 돌아갑니다. 그 믿음의 발걸음은 온 집안의 구원으로 이어졌습니다. 요한복음 4장은 민족과 신분, 과거의 상처를 뛰어넘는 예수님의 구원이 얼마나 포괄적이고 완전한지를 보여줍니다.', E'오늘의 핵심\n예수님은 유대인과 사마리아인의 장벽을 넘어, 한 여인의 영혼의 목마름을 영원한 생수로 채우시고, 온 마을을 구원으로 인도하십니다.\n\n묵상 질문\n1. 내 삶의 어떤 목마름을 세상의 우물물로 채우려 하고 있나요?\n2. 예수님께서 내 삶의 아픔과 과거를 다 아시면서도 여전히 사랑하신다는 사실이 내게 어떤 위로가 되나요?\n3. 사마리아 여인처럼 물동이를 버려두고 달려가 전할 만한 예수님과의 만남이 내게도 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-28', E'영원한 생명수이신 예수 (요한복음 5장)', E'요한복음 5장', E'베데스다 연못가에는 기적을 바라는 수많은 병자들이 모여 있었습니다. 물이 움직일 때 가장 먼저 들어가는 자가 나음을 받는다는 전설을 붙잡고, 그들은 매일같이 그곳에 누워있었습니다. 그중에서도 38년 된 병자는 가장 절망적인 상황에 있었습니다. 그에게는 물이 움직일 때 연못에 넣어줄 사람조차 없었기 때문입니다. 예수님은 바로 그를 찾아가셨습니다. "네가 낫고자 하느냐"는 예수님의 질문에 그는 자신의 불가능을 토로할 뿐이었지만, 예수님은 단호히 명령하십니다. "일어나 네 자리를 들고 걸어가라." 38년의 무력함이 한순간에 생명의 능력으로 바뀌는 놀라운 기적이 일어났습니다.\n\n그러나 종교 지도자들의 시선은 달랐습니다. 그들에게는 38년 만에 걸어가는 한 인간의 기쁨보다 안식일 규정이 더 중요했습니다. 자리를 들고 가는 것이 안식일을 범하는 일이라고 정죄하는 그들 앞에서, 예수님은 놀라운 선언을 하십니다. "내 아버지께서 이제까지 일하시니 나도 일한다." 하나님께서는 안식일에도 생명을 살리시고 은혜를 베푸시는 분이심을 보여주신 것입니다. 더 나아가 예수님은 자신이 생명을 주시는 권세와 심판하는 권세를 가진 하나님의 아들임을 분명히 밝히십니다.\n\n예수님은 당시 종교 지도자들의 근본적인 문제를 지적하십니다. "너희가 성경에서 영생을 얻는 줄 생각하고 성경을 연구하거니와 이 성경이 곧 내게 대하여 증언하는 것이니라. 그러나 너희가 영생을 얻기 위하여 내게 오기를 원하지 아니하는도다"(요 5:39-40). 성경을 연구하면서도 성경이 가리키는 예수님께로는 나아오지 않는 모순, 이것이 바로 생명 없는 종교의 비극입니다. 참된 생명은 율법의 조문을 지키는 데서 오는 것이 아니라, 생명의 주인이신 예수님께 나아갈 때 주어집니다. 38년 된 병자처럼 우리도 자신의 무력함을 인정하고 예수님의 음성에 순종할 때, 죽음에서 생명으로 옮겨지는 부활의 능력을 경험하게 될 것입니다.', E'오늘의 핵심\n38년 된 병자를 고치신 예수님은 안식일에도 생명을 살리시는 하나님의 아들이시며, 종교의 형식이 아닌 생명 그 자체이십니다.\n\n묵상 질문\n1. 38년 동안 누워있던 병자처럼, 나에게도 오랜 세월 포기하고 있던 영역이 있나요?\n2. 종교적 형식과 규정에 갇혀 정작 생명이신 예수님을 놓치고 있지는 않나요?\n3. "내 말을 듣고 또 나 보내신 이를 믿는 자는 영생을 얻었다"는 예수님의 약속이 내 삶에서 실제가 되려면 무엇이 필요할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-29', E'영원한 생명수이신 예수 (요한복음 6장)', E'요한복음 6장', E'유월절이 가까워진 때, 예수님께서는 갈릴리 바다 건너편으로 가셨습니다. 병자들을 고치시는 표적을 본 큰 무리가 따라왔고, 예수님은 그들의 육신의 필요를 아셨습니다. 빌립에게 "우리가 어디서 떡을 사서 이 사람들을 먹이겠느냐"고 물으신 것은 단순한 질문이 아니었습니다. 제자들의 믿음을 시험하시면서 동시에 더 큰 진리를 가르치려 하신 것입니다.\n\n한 아이가 가진 보리떡 다섯 개와 물고기 두 마리는 오천 명 앞에서 터무니없이 부족해 보였습니다. 그러나 예수님의 손에서 그것은 모든 사람을 배부르게 하고도 열두 바구니가 남는 풍성함이 되었습니다. 이 기적은 단순한 양식의 공급이 아니라, 예수님이 누구신지를 보여주는 표적이었습니다.\n\n그런데 무리는 표적의 의미를 놓쳤습니다. 그들은 예수님을 억지로 왕 삼으려 했고, 이튿날에는 또 떡을 얻으려 찾아왔습니다. 예수님은 그들의 마음을 꿰뚫어 보시며 말씀하셨습니다. "썩을 양식을 위하여 일하지 말고 영생하도록 있는 양식을 위하여 하라." 그리고 놀라운 선언을 하십니다. "내가 곧 생명의 떡이니라."\n\n광야에서 만나를 먹었던 조상들도 결국 죽었지만, 예수님이 주시는 떡을 먹는 자는 영원히 살 것이라는 말씀은 유대인들에게 충격이었습니다. 더욱이 "내 살을 먹고 내 피를 마시는 자는 영생을 가졌고"라는 말씀은 그들이 도저히 받아들일 수 없는 것이었습니다. 그들은 육신의 눈으로만 보았기에 영적 진리를 깨닫지 못했습니다.\n\n예수님은 우리의 일용할 양식도 공급하시지만, 더 중요한 것은 영원한 생명의 양식이 되어주신다는 사실입니다. 하늘에서 내려온 참된 떡이신 예수님을 믿고 받아들이는 것, 그것이 하나님께서 원하시는 일입니다. 오늘도 우리는 썩어질 것들을 추구하며 분주히 살아갑니다. 그러나 예수님은 우리에게 묻고 계십니다. 무엇이 당신을 진정으로 살게 하는가?', E'오늘의 핵심\n예수님은 오병이어의 기적을 통해 육신의 양식을 공급하셨지만, 궁극적으로는 자신이 하늘에서 내려온 생명의 떡임을 선포하시며 영원한 생명을 주시는 구주이심을 계시하셨습니다.\n\n묵상 질문\n1. 나는 예수님께 무엇을 구하고 있나요? 썩을 양식입니까, 영생하는 양식입니까?\n2. 내가 가진 작은 것(오병이어)을 예수님께 드릴 때 어떤 일이 일어날 수 있을까요?\n3. "내가 곧 생명의 떡이니라"는 예수님의 선언이 오늘 내 삶에 어떤 의미가 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-30', E'선한 목자이신 예수 (요한복음 9장)', E'요한복음 9장', E'날 때부터 맹인이었던 한 사람의 인생이 예수님을 만나 완전히 바뀌는 놀라운 이야기가 요한복음 9장에 펼쳐집니다. 제자들은 이 사람의 불행을 보며 누구의 죄 때문인지 묻지만, 예수님은 전혀 다른 관점을 제시하십니다. "이 사람이나 그 부모의 죄로 인한 것이 아니라 그에게서 하나님이 하시는 일을 나타내고자 하심이라"(요 9:3). 고통의 원인을 따지기보다 하나님께서 그 고통을 통해 무엇을 이루실지에 주목하라는 가르침입니다.\n\n예수님은 침과 흙을 이겨 그의 눈에 바르시고 실로암 못에 가서 씻으라고 하십니다. 실로암은 ''보냄을 받았다''는 뜻인데, 이는 단순한 치유 이상의 의미를 담고 있습니다. 그가 순종하여 씻고 돌아왔을 때, 평생 닫혀있던 눈이 열렸습니다. 그런데 이 놀라운 기적이 안식일에 일어났다는 이유로 바리새인들은 예수님을 정죄하려 합니다. 그들은 표적의 의미보다 율법 조문에만 매달렸던 것입니다.\n\n치유받은 사람은 반복되는 심문 속에서도 흔들리지 않습니다. 처음에는 "예수라 하는 그 사람"이라고 했다가, "선지자"라고 고백하고, 마침내 예수님 앞에서 "주여 내가 믿나이다"라며 경배합니다. 반면 바리새인들은 점점 더 완고해져 갑니다. 예수님은 이들에게 "너희가 맹인이 되었더라면 죄가 없으려니와 본다고 하니 너희 죄가 그대로 있느니라"고 말씀하십니다. 육신의 눈은 뜨였지만 영적으로는 맹인인 그들의 모습을 지적하신 것입니다.\n\n이 사건은 단순한 치유 기적을 넘어 영적 각성에 관한 깊은 가르침을 담고 있습니다. 참된 시각은 육신의 눈이 아닌 믿음의 눈으로 보는 것임을, 그리고 하나님의 영광은 우리의 연약함을 통해서도 나타날 수 있음을 보여줍니다.', E'오늘의 핵심\n예수님은 날 때부터 맹인된 사람을 고치시면서 육신의 치유와 함께 영적인 눈을 열어주셨고, 오히려 본다고 자부하는 종교지도자들의 영적 맹목을 드러내셨습니다.\n\n묵상 질문\n1. 내 삶의 고통과 연약함을 통해 하나님께서 나타내시려는 영광은 무엇일까요?\n2. 종교적 지식과 관습에 갇혀 예수님의 참된 모습을 보지 못하고 있는 부분은 없나요?\n3. 치유받은 맹인처럼 점진적으로 깊어지는 신앙고백을 나도 경험하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-05-31', E'선한 목자이신 예수 (요한복음 10장)', E'요한복음 10장', E'예수님께서는 9장에서 날 때부터 맹인 된 사람을 고치신 후, 바리새인들과의 대립이 심화되는 상황에서 자신의 정체성을 더욱 분명하게 드러내십니다. 목자와 양의 비유를 통해 참된 지도자의 모습이 무엇인지 가르쳐 주십니다. 양의 우리에 문으로 들어가지 않고 다른 곳으로 넘어가는 자는 절도요 강도라고 하시면서, 참된 목자는 문을 통해 들어가며 양들이 그의 음성을 알아듣는다고 말씀하십니다. \n\n예수님은 자신을 "양의 문"이자 "선한 목자"라고 선언하십니다. 문이 되신다는 것은 구원의 유일한 통로가 되심을 의미합니다. 선한 목자가 되신다는 것은 양들을 위해 목숨까지 버리는 희생적 사랑을 실천하심을 뜻합니다. 삯꾼은 위기가 닥치면 도망가지만, 선한 목자는 양을 위해 자기 생명을 내어놓습니다. 이것이 바로 십자가를 향해 가시는 예수님의 결단이었습니다.\n\n수전절 때 성전에서 유대인들이 예수님께 그리스도인지 밝히 말하라고 다그칩니다. 예수님은 이미 말했으나 그들이 믿지 않는 것은 그들이 예수님의 양이 아니기 때문이라고 하십니다. "내 양은 내 음성을 들으며 나는 그들을 알며 그들은 나를 따르느니라"(요 10:27). 참된 양은 목자의 음성을 알아듣고 따릅니다. 그리고 선한 목자이신 예수님은 자기 양들에게 영생을 주시며, 그 누구도 그들을 빼앗을 수 없다고 약속하십니다.\n\n예수님과 아버지가 하나라는 선언은 유대인들을 격분시켜 돌로 치려 했습니다. 그들에게는 신성모독으로 들렸기 때문입니다. 하지만 예수님은 자신이 행하는 일들이 곧 아버지의 일이며, 이를 통해 아버지와 자신의 하나 됨을 알 수 있다고 말씀하십니다. 요단 강 건너편으로 가신 예수님을 많은 사람들이 찾아왔고, 그곳에서 많은 이들이 예수님을 믿게 됩니다. 세례 요한의 증언이 모두 참되었음을 깨달은 것입니다.', E'오늘의 핵심\n예수님은 양들을 위해 목숨을 버리는 선한 목자이시며, 구원의 유일한 문이 되십니다. 그분의 양들은 목자의 음성을 알아듣고 따르며 영생의 약속을 받습니다.\n\n묵상 질문\n1. 내가 따르고 있는 목소리는 정말 선한 목자이신 예수님의 음성인가요?\n2. 위기의 때에도 나를 버리지 않으시는 주님의 신실하심을 어떻게 경험했나요?\n3. 영생의 확신 가운데 살아가기 위해 오늘 무엇을 결단해야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-01', E'선한 목자이신 예수 (요한복음 11장)', E'요한복음 11장', E'베다니에 사는 나사로가 병들었다는 소식이 예수님께 전해집니다. 마리아와 마르다는 오라비의 위급함을 알리며 주님의 도움을 구했지만, 예수님께서는 "이 병은 죽을 병이 아니라 하나님의 영광을 위함이요 하나님의 아들이 이로 말미암아 영광을 받게 하려 함이라"(요 11:4)고 말씀하시며 이틀을 더 머무르십니다. 제자들은 유대인들의 돌로 치려던 위협을 기억하며 두려워했지만, 예수님께서는 죽은 나사로를 살리시기 위해 베다니로 향하십니다.\n\n나사로가 무덤에 있은 지 나흘째 되던 날, 마르다는 예수님을 맞으며 "주께서 여기 계셨더라면"이라는 아쉬움을 표현합니다. 그러나 동시에 지금이라도 주님께서 구하시면 하나님께서 응답하실 것이라는 믿음을 고백합니다. 이어 마리아도 같은 말로 슬픔을 토로하자, 예수님께서는 그들과 함께 우시며 인간의 슬픔에 깊이 공감하시는 모습을 보여주십니다. \n\n무덤 앞에서 예수님께서는 하나님께 감사 기도를 드리신 후 "나사로야 나오라"고 부르십니다. 죽은 지 나흘이나 된 나사로가 살아나는 놀라운 표적이 일어납니다. 이 일을 목격한 많은 유대인들이 예수님을 믿게 되었지만, 종교 지도자들은 오히려 더욱 격렬하게 예수님을 죽이려는 계획을 세웁니다. 대제사장 가야바는 한 사람이 백성을 위해 죽는 것이 유익하다고 말하는데, 이는 자신도 모르게 예수님의 대속적 죽음을 예언한 것이었습니다.\n\n나사로의 부활 사건은 예수님께서 "나는 부활이요 생명이니"라고 선포하신 말씀이 현실이 되는 순간이었습니다. 죽음의 권세를 이기시고 생명을 주시는 분이 바로 우리 앞에 계신다는 것을 보여주신 것입니다.', E'오늘의 핵심\n예수님께서는 나사로를 살리심으로써 자신이 부활이요 생명이심을 증명하셨고, 인간의 슬픔에 함께 우시며 공감하시는 참된 구원자이심을 보여주셨습니다.\n\n묵상 질문\n1. 주님께서 나사로의 죽음을 미리 아시면서도 이틀을 더 머무르신 이유는 무엇일까요?\n2. 예수님께서 눈물을 흘리신 모습에서 우리는 어떤 위로를 받을 수 있을까요?\n3. 나에게도 "주께서 여기 계셨더라면"이라고 아쉬워하는 상황이 있나요? 그럼에도 주님을 신뢰할 수 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-02', E'예수의 고별 설교 (요한복음 14장)', E'요한복음 14장', E'예수님께서 십자가를 앞두고 제자들과 함께하시는 마지막 밤입니다. 곧 떠나야 하는 상황에서 제자들의 마음은 근심으로 가득했을 것입니다. 그런 제자들에게 예수님은 "너희는 마음에 근심하지 말라"(요 14:1)고 말씀하십니다. 이것은 단순한 위로가 아니라 확실한 약속에 근거한 선언이었습니다. 아버지의 집에 거할 곳을 예비하러 가시며, 다시 오셔서 제자들을 영접하시겠다는 약속입니다.\n\n도마가 길을 모르겠다고 고백했을 때, 예수님은 놀라운 선언을 하십니다. 길을 가르쳐 주신 것이 아니라 "내가 곧 길이요 진리요 생명"이라고 자기 자신을 제시하신 것입니다. 우리가 찾는 것이 방법이나 지식이라면, 예수님은 그 모든 것을 넘어서는 존재 자체로 우리에게 다가오십니다. 아버지께로 가는 유일한 길은 예수님 자신이며, 예수님을 통해서만 우리는 아버지를 알고 만날 수 있습니다.\n\n빌립이 아버지를 보여달라고 요청했을 때도 마찬가지입니다. 예수님은 자신을 본 자는 이미 아버지를 보았다고 말씀하십니다. 예수님과 아버지의 완전한 하나 됨이 여기서 드러납니다. 아버지가 예수님 안에, 예수님이 아버지 안에 계시는 이 신비로운 연합은 우리의 이해를 넘어서지만, 예수님의 말씀과 행하심을 통해 분명히 계시됩니다.\n\n이어서 예수님은 또 다른 놀라운 약속을 주십니다. 보혜사 성령을 보내주시겠다는 것입니다. 예수님이 떠나시지만 제자들을 고아처럼 버려두지 않으시고, 성령을 통해 영원히 함께하시겠다는 약속입니다. 성령은 진리의 영으로서 제자들에게 모든 것을 가르치시고, 예수님이 하신 말씀을 생각나게 하실 것입니다. 이는 단순한 위로를 넘어서는 능력의 약속입니다.\n\n마지막으로 예수님은 평안을 약속하십니다. 세상이 주는 평안과는 다른, 예수님만이 주실 수 있는 참된 평안입니다. 이 평안은 환경에 좌우되지 않는 평안이며, 예수님과의 관계에서 나오는 평안입니다. 예수님을 사랑하고 그의 계명을 지키는 자에게 아버지와 아들이 함께 거하시겠다는 약속은 우리가 누릴 수 있는 가장 큰 복입니다.', E'오늘의 핵심\n예수님은 떠나시지만 제자들을 고아처럼 버려두지 않으시고, 성령을 보내주시며 영원한 거처를 예비하시겠다고 약속하십니다.\n\n묵상 질문\n1. 예수님이 "길이요 진리요 생명"이라는 말씀이 오늘 나의 삶에 어떤 의미가 있나요?\n2. 내가 근심하고 두려워하는 것들을 예수님께 맡기고 그분의 평안을 받고 있나요?\n3. 성령님이 나와 함께하신다는 약속을 일상에서 어떻게 경험하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-04', E'예수의 고별 설교 (요한복음 15장)', E'요한복음 15장', E'예수님께서는 제자들과의 마지막 시간에 포도나무 비유를 통해 가장 중요한 영적 원리를 가르쳐 주십니다. "나는 참포도나무요 내 아버지는 농부라"(15:1)는 선언으로 시작되는 이 비유는 우리가 그리스도 안에서 어떻게 살아가야 하는지를 보여줍니다. 가지가 나무에 붙어 있어야만 생명을 유지하고 열매를 맺듯이, 우리도 예수님 안에 거해야만 참된 열매를 맺을 수 있습니다.\n\n이 비유에서 주목할 것은 ''거한다''는 표현이 반복적으로 나타난다는 점입니다. 예수님은 단순히 믿음을 갖는 것을 넘어, 지속적으로 그분 안에 머무는 삶을 요구하십니다. 그리고 그 거함의 구체적인 모습은 사랑으로 나타납니다. 아버지께서 아들을 사랑하신 것같이 예수님이 우리를 사랑하셨고, 이제 우리도 그 사랑 안에 거하며 서로 사랑해야 한다는 것입니다. 놀랍게도 예수님은 이렇게 사랑 안에 거하는 제자들을 더 이상 종이 아닌 ''친구''라고 부르십니다. 주인과 종의 관계가 아닌, 모든 것을 나누는 친밀한 관계로 초청하신 것입니다.\n\n그러나 이 사랑의 관계는 세상과의 갈등을 동반합니다. 예수님은 제자들이 세상의 미움을 받게 될 것을 분명히 말씀하십니다. 세상이 먼저 예수님을 미워했듯이, 그분께 속한 제자들도 미움을 받게 됩니다. 하지만 이 어려움 가운데서도 소망이 있습니다. 바로 아버지께로부터 오시는 진리의 성령, 보혜사께서 예수님을 증언하실 것이며, 제자들도 그 증언에 동참하게 될 것입니다.\n\n포도나무에 붙어 있는 가지처럼, 우리의 생명과 열매는 전적으로 그리스도께 의존합니다. 내 힘과 노력으로 무언가를 이루려 하기보다, 먼저 그분 안에 거하는 것, 그분의 사랑 안에 머무는 것이 우선입니다. 오늘도 참포도나무이신 예수님께 깊이 연결되어, 그분의 생명으로 살아가는 하루가 되기를 소망합니다.', E'오늘의 핵심\n예수님은 참포도나무로서 우리가 그분 안에 거할 때만 열매를 맺을 수 있음을 가르치시며, 그 거함의 핵심은 서로 사랑하는 것임을 말씀하십니다.\n\n묵상 질문\n1. 나는 지금 포도나무이신 예수님께 얼마나 깊이 연결되어 있나요?\n2. 예수님이 나를 ''친구''라 부르신다는 사실이 내 삶에 어떤 변화를 가져다주나요?\n3. 세상의 미움을 받을 때도 사랑 안에 거할 수 있는 힘은 어디서 오나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-05', E'예수의 십자가 사역 (요한복음 18장)', E'요한복음 18장', E'예수님은 모든 것을 아셨습니다. 유다가 군대를 이끌고 올 것도, 자신이 십자가에서 죽게 될 것도 알고 계셨습니다. 그런데 놀라운 것은 예수님이 숨거나 피하지 않으셨다는 사실입니다. 오히려 먼저 나아가셔서 "너희가 누구를 찾느냐"고 물으셨습니다. "내가 그니라"라고 말씀하시자 무리가 땅에 엎드러졌습니다. 이 장면은 잡히러 온 자들 앞에서도 예수님이 여전히 주권자이셨음을 보여줍니다. 예수님의 체포는 당하신 것이 아니라, 스스로 내어주신 것이었습니다.\n\n그 순간에도 예수님은 제자들을 지키셨습니다. "나를 찾거든 이 사람들이 가는 것은 용납하라." 아버지께서 맡기신 자를 하나도 잃지 않겠다는 그 약속을 끝까지 지키신 것입니다. 반면 베드로는 목숨을 걸고 따르겠다던 고백과 달리 세 번이나 예수님을 부인합니다. 추운 밤, 불 앞에 서서 몸을 녹이던 그 모습은 두려움 앞에서 무너지는 우리의 솔직한 자화상이기도 합니다.\n\n빌라도 앞에서 예수님은 "내 나라는 이 세상에 속한 것이 아니니라"고 선언하셨습니다. 세상의 권력과 군대로 세우는 나라가 아니라 진리로 세우시는 나라입니다. 빌라도는 "진리가 무엇이냐"고 물었지만 답을 기다리지 않았습니다. 진리이신 분이 바로 눈앞에 서 계셨는데도 알아보지 못한 것입니다. 결국 빌라도는 죄 없음을 알면서도 군중의 외침에 예수님을 넘기고, 무리는 예수님 대신 강도 바라바를 택합니다.\n\n직장에서, 학교에서, 관계 속에서 우리도 ''내가 그리스도인이냐''는 질문 앞에 서게 됩니다. 베드로처럼 두려워 부인할 때도 있을 것입니다. 그러나 우리를 끝까지 지키시는 예수님의 사랑을 기억한다면, 우리도 그분의 진리 앞에 담대히 설 수 있을 것입니다.', E'오늘의 핵심\n예수님은 자신의 고난을 미리 아시면서도 스스로 십자가의 길로 나아가셨고, 그 과정에서도 제자들을 끝까지 보호하시며 하나님의 뜻을 이루셨습니다.\n\n묵상 질문\n1. 예수님이 스스로 체포당하러 나가신 이유는 무엇일까요?\n2. 베드로의 부인을 통해 나의 연약함을 어떻게 돌아볼 수 있을까요?\n3. 빌라도처럼 진리를 외면하고 있는 나의 모습은 없나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-06', E'예수의 십자가 사역 (요한복음 19장)', E'요한복음 19장', E'빌라도의 법정에서 예수님은 채찍에 맞으시고 가시관을 쓰셨습니다. 자색 옷을 입히고 조롱하는 군인들 앞에서도 예수님은 침묵하셨습니다. 빌라도는 예수님께서 죄가 없음을 알았지만, 유대인들의 압력에 굴복하고 말았습니다. "이 사람을 놓으면 가이사의 충신이 아니니이다"라는 그들의 협박은 빌라도의 정치적 생명을 위협하는 것이었습니다. 결국 빌라도는 진리보다 권력을, 정의보다 안위를 택했습니다.\n\n예수님은 빌라도에게 말씀하셨습니다. "위에서 주지 아니하셨더라면 나를 해할 권한이 없었으리니." 이 말씀은 십자가 사건조차도 하나님의 주권 아래 있음을 보여줍니다. 세상의 권세자들이 예수님을 심판하는 것처럼 보였지만, 실상은 하나님께서 인류 구원의 계획을 이루어 가시는 과정이었습니다. 대제사장들이 "가이사 외에는 우리에게 왕이 없나이다"라고 외친 것은 하나님의 백성이 얼마나 타락했는지를 보여주는 비극적인 고백이었습니다.\n\n골고다 언덕에서 예수님은 두 강도와 함께 십자가에 못 박히셨습니다. 빌라도가 쓴 ''나사렛 예수 유대인의 왕''이라는 패는 히브리어, 로마어, 헬라어로 기록되었습니다. 이는 예수님의 왕 되심이 온 세상에 선포되는 순간이었습니다. 십자가 아래에서 군인들은 예수님의 옷을 나누며 제비를 뽑았고, 이는 시편의 예언을 성취하는 것이었습니다.\n\n십자가 위에서도 예수님은 어머니를 돌보셨습니다. 사랑하는 제자에게 어머니를 부탁하시는 모습은 끝까지 사랑을 실천하시는 주님의 성품을 보여줍니다. 그리고 "다 이루었다"는 마지막 선언과 함께 숨을 거두셨습니다. 이는 패배의 탄식이 아니라 승리의 선언이었습니다. 인류 구원을 위한 하나님의 계획이 완성되는 순간이었습니다.\n\n예수님이 돌아가신 후, 숨어있던 두 제자가 나타났습니다. 아리마대 요셉과 니고데모는 용기를 내어 예수님의 시신을 거두었습니다. 백 리트라나 되는 향품을 가져온 니고데모의 행동은 왕의 장례에 합당한 예우였습니다. 새 무덤에 장사되신 예수님의 모습은 죄 없으신 분이 우리의 죄를 대신 지셨음을 보여줍니다. 어둠이 가장 짙을 때, 하나님은 이미 부활의 새벽을 준비하고 계셨습니다.', E'오늘의 핵심\n십자가는 세상의 눈에는 실패와 죽음의 자리였지만, 하나님의 계획 안에서는 인류 구원이 완성되는 영광의 자리였습니다.\n\n묵상 질문\n1. 빌라도처럼 진리를 알면서도 세상의 압력에 굴복한 경험이 있나요?\n2. 예수님께서 십자가에서 "다 이루었다"고 하신 말씀이 내 삶에 어떤 의미가 있나요?\n3. 아리마대 요셉과 니고데모처럼 두려움을 극복하고 신앙을 고백해야 할 때는 언제인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-07', E'예수의 십자가 사역 (요한복음 20장)', E'요한복음 20장', E'안식 후 첫날 이른 새벽, 막달라 마리아가 무덤을 찾았을 때 돌이 옮겨진 빈 무덤을 발견합니다. 그녀는 즉시 베드로와 요한에게 달려가 이 소식을 전했고, 두 제자는 서둘러 무덤으로 향합니다. 무덤 안에는 예수님의 시신은 없고 세마포와 머리 수건만 가지런히 놓여 있었습니다. 특별히 머리 수건이 따로 개어져 있었다는 세밀한 묘사는 이것이 도둑질이 아닌 질서정연한 부활의 현장임을 보여줍니다. 요한은 이 광경을 보고 비로소 믿게 되었다고 고백합니다.\n\n홀로 무덤가에 남아 울고 있던 마리아에게 부활하신 주님이 먼저 나타나십니다. 처음엔 동산지기로 착각했지만, 예수님께서 그녀의 이름을 부르시자 마리아는 "랍오니"라고 응답합니다. 이 친밀한 만남은 부활이 단순한 역사적 사건이 아니라 개인적이고 인격적인 만남임을 보여줍니다. 예수님은 마리아에게 제자들에게 가서 부활의 소식을 전하라고 명하십니다. "내가 내 아버지 곧 너희 아버지께로 올라간다"는 이 메시지는 예수님의 부활로 인해 우리도 하나님을 아버지로 부를 수 있게 되었음을 선포합니다.\n\n저녁이 되자 유대인들을 두려워하며 문을 걸어 잠근 채 숨어있던 제자들에게 부활하신 예수님이 나타나셨습니다. "너희에게 평강이 있을지어다"라는 인사와 함께 손과 옆구리의 상처를 보여주시며 제자들의 두려움을 평강으로 바꾸어 주십니다. 그리고 숨을 내쉬시며 "성령을 받으라"고 말씀하시는데, 이는 창조 때 생기를 불어넣으신 것처럼 새로운 창조의 시작을 알리는 것입니다. 아버지께서 예수님을 보내신 것같이 이제 예수님께서 제자들을 세상으로 파송하십니다.\n\n그 자리에 없었던 도마는 다른 제자들의 증언을 믿지 못하고 직접 못 자국을 만져보겠다고 고집합니다. 여드레 후 예수님은 도마의 요구대로 손과 옆구리를 보이시며 "믿음 없는 자가 되지 말고 믿는 자가 되라"고 권면하십니다. 이에 도마는 "나의 주님이시요 나의 하나님이시니이다"라는 가장 분명한 신앙고백으로 응답합니다. 예수님은 보지 못하고 믿는 자들이 복되다고 선언하시는데, 이는 오늘날 우리를 향한 축복의 말씀이기도 합니다.', E'오늘의 핵심\n부활하신 예수님은 두려움에 갇힌 제자들을 찾아오셔서 평강을 주시고, 성령으로 새롭게 하시며, 세상을 향한 사명자로 파송하십니다.\n\n묵상 질문\n1. 빈 무덤 앞에서 울고 있던 마리아처럼, 나도 주님의 부재를 경험하며 슬퍼한 적이 있나요?\n2. 두려움에 문을 걸어 잠근 제자들에게 찾아오신 주님이 내게도 어떤 평강을 주실까요?\n3. "보지 못하고 믿는 자가 복되다"는 말씀이 오늘 나의 신앙에 어떤 도전과 위로를 주나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-08', E'예수의 십자가 사역 (요한복음 21장)', E'요한복음 21장', E'부활하신 예수님이 디베랴 호숫가에 다시 나타나셨습니다. 베드로와 제자들은 밤새 그물을 던졌지만 아무것도 잡지 못한 채 새벽을 맞이했습니다. 바로 그때 낯선 사람이 "그물을 배 오른편에 던지라"고 말씀하셨고, 순종했을 때 놀라운 일이 일어났습니다. 153마리의 큰 물고기로 그물이 가득 찼지만 찢어지지 않았습니다. 이 기적을 통해 제자들은 그분이 주님이심을 알아보았습니다.\n\n갈릴리 호수는 제자들에게 특별한 곳이었습니다. 처음 부르심을 받았던 곳이자, 이제는 좌절과 실패 후에 돌아온 일상의 자리였습니다. 그런데 부활하신 주님은 바로 그 일상의 자리에서 제자들을 다시 만나주셨습니다. 숯불 위에는 이미 생선이 놓여 있었고 떡도 준비되어 있었습니다. 제자들을 위해 아침을 준비하신 주님의 섬세한 사랑이 드러나는 순간입니다.\n\n조반을 나눈 후, 예수님은 베드로에게 세 번 물으셨습니다. "네가 나를 사랑하느냐?" 베드로가 세 번 부인했던 그 아픔의 자리에서, 주님은 세 번의 사랑 고백을 통해 그를 회복시키셨습니다. 그리고 "내 양을 먹이라"는 새로운 사명을 주셨습니다. 실패한 제자를 목자로 세우시는 놀라운 은혜였습니다.\n\n예수님은 베드로의 미래도 말씀하셨습니다. 젊어서는 스스로 띠를 띠고 다녔지만, 늙어서는 팔을 벌리고 남이 띠를 띠워 원치 않는 곳으로 데려갈 것이라고 하셨습니다. 전승에 의하면 베드로는 후에 로마에서 십자가에 거꾸로 매달려 순교했다고 합니다. 그러나 이제 베드로에게 중요한 것은 다른 제자와 비교하는 것이 아니라 "너는 나를 따르라"는 주님의 부르심에 응답하는 것이었습니다.\n\n요한은 이 모든 일을 목격하고 기록한 증인이었습니다. 그는 예수님이 행하신 일이 너무나 많아서 다 기록한다면 이 세상도 그 책들을 두기에 부족할 것이라고 고백합니다. 복음서는 끝났지만, 부활하신 주님과 함께하는 제자들의 새로운 이야기는 이제 막 시작되고 있었습니다.', E'오늘의 핵심\n부활하신 예수님은 실패와 좌절 속에 있는 제자들의 일상으로 찾아오셔서 그들을 회복시키시고, 새로운 사명을 주셨습니다.\n\n묵상 질문\n1. 내 삶의 실패와 좌절의 자리에서도 주님이 나를 찾아오신다고 믿으시나요?\n2. 베드로처럼 주님께 사랑을 고백하며 회복된 경험이 있으신가요?\n3. "너는 나를 따르라"는 주님의 부르심에 오늘 나는 어떻게 응답하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-09', E'세워지는 초기교회 (사도행전 3장)', E'사도행전 3장', E'예루살렘 성전은 유대인들의 기도 생활의 중심지였습니다. 제구시, 곧 오후 3시는 유대인들의 정규 기도 시간이었고, 베드로와 요한도 이 시간에 맞추어 성전으로 올라갑니다. 성전 미문에는 태어날 때부터 걷지 못하는 한 사람이 있었습니다. 날마다 이곳에 앉아 성전에 들어가는 사람들에게 구걸하며 살아가던 그에게 베드로와 요한이 다가갑니다.\n\n베드로의 선언은 단순하면서도 강력했습니다. "은과 금은 내게 없거니와 내게 있는 이것을 네게 주노니 나사렛 예수 그리스도의 이름으로 일어나 걸으라"(행 3:6). 물질적인 도움을 기대했던 그 사람은 예상치 못한 선물을 받게 됩니다. 나사렛 예수의 이름으로 선포된 치유의 능력이 그의 발과 발목에 힘을 주었고, 평생 앉아만 있던 그가 뛰어 서서 걷게 되었습니다.\n\n이 놀라운 일을 목격한 백성들이 솔로몬의 행각으로 모여들자, 베드로는 중요한 메시지를 전합니다. 이 기적은 사도들의 개인적 능력이나 경건함 때문이 아니라, 바로 그들이 십자가에 못 박은 예수님의 이름의 능력 때문이라는 것입니다. 베드로는 예수님을 거부하고 죽음에 넘긴 그들의 과거를 상기시키면서도, 하나님께서 죽은 자 가운데서 그를 살리셨다는 부활의 복음을 선포합니다.\n\n특별히 베드로는 그들의 행동이 무지에서 비롯되었음을 인정하면서도, 이제는 회개하고 돌이킬 때임을 강조합니다. 구약의 모든 선지자들이 예언한 그리스도가 바로 예수님이시며, 아브라함에게 약속하신 복이 예수 그리스도를 통해 성취되었다는 것입니다. 하나님께서는 그의 종 예수를 먼저 유대인들에게 보내셔서 그들이 악에서 돌이켜 복을 받게 하셨습니다.\n\n성전 미문의 기적은 단순한 치유 사건이 아니라, 예수 그리스도의 이름이 지닌 능력과 권위를 증명하는 표적이었습니다. 동시에 이스라엘 백성들에게 회개와 믿음으로 나아올 것을 촉구하는 하나님의 은혜로운 초청이었습니다.', E'오늘의 핵심\n예수 그리스도의 이름으로 행해진 치유의 기적은 십자가와 부활의 복음을 증거하는 능력 있는 표적이 되었고, 이를 통해 회개와 믿음의 문이 열렸습니다.\n\n묵상 질문\n1. 물질보다 더 귀한 것을 줄 수 있는 믿음이 내게 있는지 돌아봅시다. 내가 가진 예수님의 이름의 능력을 어떻게 나눌 수 있을까요?\n2. 베드로처럼 담대하게 복음을 전할 기회가 왔을 때, 나는 어떻게 반응하고 있나요?\n3. 하나님께서 내 삶에 행하신 놀라운 일들을 기억하며, 오늘 누구에게 그 은혜를 나눌 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-11', E'세워지는 초기교회 (사도행전 4장)', E'사도행전 4장', E'성전 미문에서 일어난 치유의 기적은 예루살렘 전체를 뒤흔들었습니다. 하루아침에 오천 명이 믿게 되는 놀라운 부흥이 일어났지만, 동시에 종교 지도자들의 격렬한 반대도 시작되었습니다. 제사장들과 성전 맡은 자들, 그리고 부활을 믿지 않는 사두개인들은 사도들이 예수 안에 죽은 자의 부활이 있다고 전하는 것을 견딜 수 없었습니다. 그들은 베드로와 요한을 체포하여 감옥에 가두고, 이튿날 대제사장 안나스와 가야바를 비롯한 최고 권력자들이 모여 심문을 시작했습니다.\n\n"너희가 무슨 권세와 누구의 이름으로 이 일을 행하였느냐"는 그들의 질문 앞에서 베드로는 성령 충만함으로 담대히 선포합니다. 너희가 십자가에 못 박았지만 하나님께서 살리신 나사렛 예수 그리스도의 이름으로 이 사람이 온전하게 되었다고 증언합니다. 더 나아가 베드로는 시편을 인용하며 예수님이 바로 건축자들이 버린 돌이지만 모퉁이의 머릿돌이 되신 분이며, 천하 인간에 구원을 얻을 만한 다른 이름이 없다고 선포합니다.\n\n종교 지도자들은 베드로와 요한의 담대함에 당황했습니다. 그들은 이 두 사람을 본래 학문 없는 평범한 사람으로 알고 있었는데, 지금 보니 전혀 다른 사람들이었습니다. 게다가 치유받은 사람이 함께 서 있으니 부인할 수도 없었습니다. 결국 그들은 예수의 이름으로 말하지도 가르치지도 말라고 위협하며 놓아줄 수밖에 없었습니다. \n\n놓임을 받은 사도들은 동료들에게 돌아가 모든 일을 보고했고, 그들은 한마음으로 하나님께 기도를 올렸습니다. 주님의 종들이 담대히 말씀을 전할 수 있게 해달라고, 예수의 이름으로 표적과 기사가 일어나게 해달라고 간구했습니다. 그 기도가 끝나자 모인 곳이 진동하며 모두가 성령 충만함을 받아 더욱 담대히 하나님의 말씀을 전하게 되었습니다. 이러한 성령의 역사는 공동체의 삶에도 나타났습니다. 믿는 이들이 한마음 한뜻이 되어 모든 물건을 서로 통용하고, 자기 것이라 주장하는 사람이 하나도 없었습니다. 바나바를 비롯한 많은 이들이 자발적으로 재산을 팔아 가난한 이들과 나누었습니다. 이것이 성령께서 인도하시는 초대교회의 아름다운 모습이었습니다.', E'오늘의 핵심\n권력의 위협 앞에서도 성령 충만한 사도들은 예수 그리스도만이 구원자임을 담대히 선포했고, 초대교회는 한마음으로 기도하며 모든 것을 나누는 사랑의 공동체로 성장했습니다.\n\n묵상 질문\n1. 세상의 권세 앞에서도 흔들리지 않는 담대함은 어디에서 오는 것일까요?\n2. 나의 삶에서 예수님의 이름 외에 다른 것에 의지하고 있는 영역은 없나요?\n3. 한마음으로 기도하고 서로 나누는 공동체를 위해 내가 먼저 실천할 수 있는 것은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-12', E'세워지는 초기교회 (사도행전 5장)', E'사도행전 5장', E'초대교회는 성령의 놀라운 역사 가운데 자라가고 있었습니다. 그러나 교회의 성장과 함께 내부의 어두운 면도 드러나기 시작합니다. 아나니아와 삽비라 부부는 자신들의 소유를 팔아 그 값의 일부를 감추고 나머지만 사도들에게 가져왔습니다. 문제는 그들이 전부를 드린 것처럼 거짓말했다는 것입니다. 베드로는 이들의 거짓을 꿰뚫어보며 "사람에게 거짓말한 것이 아니요 하나님께로다"(행 5:4)라고 선언합니다. 이 사건은 초대교회에 큰 충격과 경외심을 불러일으켰고, 하나님께서 교회의 순결을 얼마나 중요하게 여기시는지를 보여주었습니다.\n\n한편 사도들의 손을 통해 많은 표적과 기사가 일어나자 믿는 자들의 수가 더욱 늘어났고, 심지어 베드로의 그림자라도 병든 자에게 닿기를 바라는 이들이 생겨났습니다. 이러한 부흥의 물결은 종교 지도자들의 시기심을 불러일으켰고, 그들은 사도들을 잡아 옥에 가두었습니다. 그러나 하나님은 천사를 보내어 옥문을 열고 사도들을 이끌어내시며 "가서 성전에 서서 이 생명의 말씀을 다 백성에게 말하라"고 명령하셨습니다.\n\n공회 앞에 선 사도들은 "사람보다 하나님께 순종하는 것이 마땅하니라"고 담대히 선포했습니다. 격분한 종교 지도자들이 사도들을 죽이려 할 때, 존경받는 율법교사 가말리엘이 지혜로운 조언을 합니다. 그는 이 일이 사람에게서 났으면 스스로 무너질 것이요, 하나님께로부터 났으면 막을 수 없을 것이라고 말했습니다. 결국 사도들은 채찍질을 당한 후 풀려났지만, 오히려 그리스도의 이름을 위해 고난받는 것을 영광으로 여기며 기뻐했습니다. 그들은 날마다 성전에서나 집에서나 예수가 그리스도임을 전파하기를 멈추지 않았습니다.', E'오늘의 핵심\n하나님은 교회의 거룩함을 지키시며, 핍박 가운데서도 복음 전파의 사명을 멈추지 않는 사도들을 통해 하나님 나라를 확장하십니다.\n\n묵상 질문\n1. 아나니아와 삽비라처럼 하나님 앞에서 진실하지 못한 모습은 없는지 돌아보셨나요?\n2. "사람보다 하나님께 순종하는 것이 마땅하다"는 말씀이 내 삶에서 어떤 도전을 주나요?\n3. 그리스도를 위한 고난을 기쁨으로 여길 수 있는 믿음을 어떻게 가질 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-13', E'그리스도인 핍박과 열방을 향한 흩어짐 (사도행전 6장)', E'사도행전 6장', E'예루살렘 교회가 성장하면서 교회 내부에 첫 번째 갈등이 발생합니다. 헬라파 유대인들이 히브리파 사람들을 원망하기 시작한 것입니다. 그 이유는 매일 시행되던 구제 사역에서 헬라파 과부들이 소외되고 있었기 때문입니다. 초대교회는 모든 물건을 서로 통용하며 나누는 아름다운 공동체였지만, 교회가 커지면서 구제 사역의 사각지대가 생겨난 것입니다.\n\n사도들은 이 문제를 진지하게 받아들입니다. 그들은 자신들이 구제 사역까지 담당하다 보면 가장 중요한 말씀 사역과 기도에 집중할 수 없음을 깨닫습니다. 그래서 "성령과 지혜가 충만하여 칭찬 받는 사람 일곱"(행 6:3)을 택하여 이 일을 맡기기로 결정합니다. 이는 단순한 업무 분담이 아니라, 각자의 은사에 따라 사역을 나누는 지혜로운 결정이었습니다.\n\n선출된 일곱 집사의 이름을 보면 모두 헬라식 이름을 가진 사람들입니다. 이는 초대교회가 문제를 일으킨 헬라파의 입장을 충분히 고려하여, 그들 가운데서 일꾼을 세웠음을 보여줍니다. 교회는 갈등을 덮거나 무시하지 않고, 소외된 이들의 목소리에 귀를 기울이며 그들을 섬길 사람을 세운 것입니다.\n\n이렇게 일꾼들이 세워지자 놀라운 일이 일어납니다. 하나님의 말씀이 왕성해지고, 예루살렘의 제자 수가 더욱 늘어났으며, 심지어 제사장들까지도 복음에 순종하게 된 것입니다. 스데반은 구제 사역뿐 아니라 은혜와 권능이 충만하여 큰 기사와 표적을 행합니다. 그러나 이러한 능력은 곧 반대자들의 시기와 모함을 불러일으켰고, 거짓 증인들이 그를 모세와 하나님을 모독했다고 고발합니다. \n\n공회 앞에 선 스데반의 얼굴이 천사의 얼굴과 같았다는 것은, 그가 하나님의 임재 가운데 있었음을 보여줍니다. 초대교회는 내부의 갈등을 지혜롭게 해결하여 더욱 성장했지만, 동시에 외부로부터의 박해도 시작되고 있었습니다.', E'오늘의 핵심\n초대교회는 내부 갈등을 은혜롭게 해결하며 각자의 은사에 따라 사역을 분담했고, 이를 통해 교회는 더욱 건강하게 성장할 수 있었습니다.\n\n묵상 질문\n1. 우리 교회나 공동체에서 소외되고 있는 사람들은 누구이며, 그들의 필요에 어떻게 응답하고 있나요?\n2. 나에게 주신 은사를 따라 섬길 수 있는 사역은 무엇일까요?\n3. 갈등이 생길 때 덮어두기보다 지혜롭게 해결하려 노력하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-14', E'그리스도인 핍박과 열방을 향한 흩어짐 (사도행전 7장)', E'사도행전 7장', E'스데반은 산헤드린 공회 앞에서 이스라엘의 역사를 통해 하나님의 구원 계획을 증거합니다. 그의 설교는 아브라함부터 시작하여 족장들, 요셉, 모세를 거쳐 솔로몬 성전에 이르기까지 이스라엘의 전체 역사를 관통합니다. \n\n스데반이 전하는 메시지의 핵심은 하나님께서 언제나 특정한 장소나 건물에 제한되지 않으시고 자유롭게 일하신다는 것입니다. 아브라함은 약속의 땅에서 한 뼘의 땅도 소유하지 못했지만 하나님과 동행했고, 요셉은 애굽에서 노예로 팔렸지만 그곳에서 하나님의 구원 도구가 되었습니다. 모세는 애굽의 왕궁이 아닌 미디안 광야에서 하나님을 만났으며, 이스라엘 백성은 성전이 없는 광야에서도 하나님께 예배드렸습니다.\n\n특별히 스데반은 이스라엘 역사 속에서 반복되는 패턴을 지적합니다. 하나님께서 보내신 지도자들을 백성들이 처음에는 거부했다가 나중에 인정하는 일이 계속되었다는 것입니다. 요셉은 형들에게 미움받아 팔렸고, 모세는 동족에게 "누가 너를 관리와 재판장으로 세웠느냐"라는 거절을 당했습니다. 그러나 하나님은 거절당한 이들을 통해 구원을 이루셨습니다.\n\n스데반의 설교는 단순한 역사 회고가 아닙니다. 그는 조상들이 모세를 거부하고 금송아지를 만들어 우상숭배에 빠졌듯이, 지금 유대 지도자들도 의인이신 예수님을 거부하고 십자가에 못 박았다고 지적합니다. "지극히 높으신 이는 손으로 지은 곳에 계시지 아니하시나니"(행 7:48)라는 선언은 성전 중심의 종교에 안주하면서 정작 성전의 주인이신 하나님과 그의 메시아를 거부한 그들의 모순을 드러냅니다.\n\n이 긴 설교를 통해 스데반은 기독교 신앙이 유대교의 단순한 이단이 아니라, 오히려 아브라함부터 시작된 하나님의 구원 역사의 정당한 계승자임을 증명합니다. 성전과 율법을 넘어서는 하나님의 우주적 통치, 그리고 예수 그리스도를 통한 새로운 구원의 시대가 열렸음을 선포한 것입니다.', E'오늘의 핵심\n스데반은 이스라엘 역사를 통해 하나님께서 특정 장소나 건물에 제한되지 않으시며, 거절당한 자들을 통해 구원을 이루신다는 진리를 증거합니다.\n\n묵상 질문\n1. 내가 하나님을 특정한 장소나 형식 안에 가두려 하지는 않나요?\n2. 하나님께서 보내신 메시지나 사람을 거부한 적은 없었나요?\n3. 신앙의 본질보다 종교적 형식에 안주하고 있지는 않은지 돌아봅시다.');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-15', E'그리스도인 핍박과 열방을 향한 흩어짐 (사도행전 8장)', E'사도행전 8장', E'예루살렘 교회에 큰 박해가 시작되었습니다. 스데반의 순교 이후, 사울을 비롯한 박해자들은 각 집을 돌며 신자들을 끌어다 옥에 가두었습니다. 사도들을 제외한 대부분의 성도들은 유대와 사마리아 전 지역으로 흩어져야 했습니다. 그러나 놀라운 것은 흩어진 사람들이 도망만 간 것이 아니라 "두루 다니며 복음의 말씀을 전했다"는 사실입니다. 박해가 오히려 복음 전파의 통로가 된 것입니다.\n\n특별히 빌립은 사마리아 성으로 내려가 그리스도를 전파했습니다. 유대인들이 멸시하던 사마리아에 복음이 전해진 것은 하나님 나라의 경계가 확장되는 중요한 전환점이었습니다. 더러운 귀신들이 쫓겨나고 병자들이 치유되면서 그 성에는 큰 기쁨이 충만했습니다. 마술사 시몬까지도 빌립의 사역을 보고 믿음을 고백하며 세례를 받았습니다. 하지만 베드로와 요한이 와서 성령을 받게 하는 안수를 하자, 시몬은 돈으로 그 권능을 사려 했습니다. 베드로는 단호하게 그의 잘못된 동기를 지적하며 회개를 촉구했습니다. 하나님의 은사는 결코 돈으로 살 수 있는 것이 아님을 분명히 보여주는 대목입니다.\n\n이어서 성령께서는 빌립을 광야 길로 인도하셨습니다. 그곳에서 빌립은 예루살렘에서 예배하고 돌아가던 에디오피아 내시를 만났습니다. 내시는 이사야서를 읽고 있었지만 그 의미를 깨닫지 못하고 있었습니다. 빌립은 그가 읽던 바로 그 본문에서 시작하여 예수 그리스도의 복음을 전했습니다. 내시는 즉시 믿음으로 반응하여 세례를 받았고, 기쁨으로 충만하여 자기 길을 갔습니다. 성령께서 빌립을 이끌어 가신 후, 그는 아소도에서부터 가이사랴까지 여러 성을 다니며 계속해서 복음을 전했습니다. 박해로 인한 흩어짐이 오히려 예루살렘을 넘어 유대와 사마리아, 그리고 이방 땅끝까지 복음이 전파되는 하나님의 섭리가 되었던 것입니다.', E'오늘의 핵심\n예루살렘 교회의 박해와 흩어짐은 오히려 복음이 사마리아와 이방인에게까지 전파되는 하나님의 섭리가 되었습니다.\n\n묵상 질문\n1. 내 삶의 어려움과 흩어짐이 오히려 복음 전파의 기회가 될 수 있을까요?\n2. 하나님의 은사를 세상적 방법으로 얻으려 한 적은 없나요?\n3. 말씀을 갈급해하는 영혼을 만날 때 복음을 전할 준비가 되어 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-16', E'그리스도인 핍박과 열방을 향한 흩어짐 (사도행전 9장)', E'사도행전 9장', E'초대교회를 향한 박해의 선봉에 섰던 사울의 이야기가 사도행전 9장에 펼쳐집니다. "주의 제자들에 대하여 여전히 위협과 살기가 등등하여"(행 9:1) 대제사장에게서 공문을 받아 다메섹으로 향하던 사울은, 그 길에서 부활하신 예수님을 만나게 됩니다. 홀연히 하늘로부터 비춘 빛과 함께 들려온 음성은 사울의 인생을 완전히 뒤바꾸어 놓았습니다.\n\n주님께서는 사울에게 "네가 어찌하여 나를 박해하느냐"고 물으셨는데, 이는 교회를 박해하는 것이 곧 그리스도를 박해하는 것임을 보여줍니다. 교회는 그리스도의 몸이며, 성도 한 사람 한 사람이 주님과 연합되어 있다는 놀라운 진리가 여기에 담겨 있습니다. \n\n사울은 사흘 동안 앞을 보지 못하고 먹지도 마시지도 못한 채 어둠 속에 머물렀습니다. 이 시간은 단순한 신체적 고통의 시간이 아니라, 자신의 과거를 돌아보고 새로운 부르심을 받아들이는 영적 전환의 시간이었습니다. 한편 아나니아는 두려움 속에서도 주님의 명령에 순종하여 사울을 찾아갑니다. 박해자였던 사울을 "형제"라 부르며 안수하는 아나니아의 모습은 용서와 화해의 복음이 무엇인지를 보여줍니다.\n\n회심한 사울은 즉시 회당에서 예수가 하나님의 아들이심을 전파하기 시작했습니다. 한때 교회를 핍박하던 자가 이제는 복음을 전하는 자가 된 것입니다. 이러한 극적인 변화는 유대인들을 당혹하게 만들었고, 급기야 그들은 사울을 죽이려는 음모를 꾸미게 됩니다. 박해자에서 피박해자가 된 사울의 모습은 복음의 능력이 얼마나 강력한지를 증거합니다.\n\n예루살렘 교회는 처음에 사울을 받아들이기를 주저했습니다. 그러나 바나바가 중재자로 나서서 사울의 회심을 증언했고, 이를 통해 사울은 사도들과 교제를 나눌 수 있게 되었습니다. 바나바의 이러한 역할은 교회 공동체 안에서 화해와 신뢰를 세워가는 일이 얼마나 중요한지를 가르쳐 줍니다. 하나님께서는 교회의 가장 큰 박해자를 이방인의 사도로 변화시키셨고, 이를 통해 복음이 온 세계로 퍼져나가는 새로운 장을 열어가셨습니다.', E'오늘의 핵심\n교회를 박해하던 사울이 부활하신 예수님을 만나 회심함으로써, 하나님께서는 가장 강력한 반대자를 가장 열정적인 복음 전파자로 변화시키셨습니다.\n\n묵상 질문\n1. 내가 거부하고 있는 하나님의 부르심은 없는지 돌아보셨나요?\n2. 과거의 실패와 죄가 하나님의 은혜로 어떻게 변화될 수 있을까요?\n3. 바나바처럼 화해의 다리 역할을 감당해야 할 상황이 있다면 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-18', E'베드로와 고넬료의 만남 (사도행전 1장)', E'사도행전 1장', E'부활하신 예수님께서 사십 일 동안 제자들에게 나타나셔서 하나님 나라의 일을 말씀하십니다. 이제 승천을 앞두신 주님은 제자들에게 마지막 명령을 주십니다. "예루살렘을 떠나지 말고 내게서 들은 바 아버지께서 약속하신 것을 기다리라"(행 1:4). 제자들은 여전히 이스라엘 나라의 정치적 회복을 기대하고 있었지만, 예수님은 그들에게 전혀 다른 차원의 사명을 맡기십니다. 성령이 임하시면 예루살렘과 온 유대와 사마리아와 땅 끝까지 이르러 주님의 증인이 되리라는 것입니다.\n\n감람산에서 예수님이 하늘로 올라가시는 모습을 목격한 제자들은 예루살렘으로 돌아와 다락방에 모입니다. 베드로와 요한을 비롯한 열한 제자들, 여자들과 예수님의 어머니 마리아, 그리고 예수님의 형제들까지 약 백이십 명이 한마음으로 기도에 전념합니다. 이들은 더 이상 두려움에 떨며 숨어있는 사람들이 아니었습니다. 부활의 주님을 만난 확신과 성령의 약속을 붙든 믿음으로 충만한 공동체였습니다.\n\n기도하던 중 베드로가 일어나 유다를 대신할 사도를 선출하자고 제안합니다. 그들은 예수님의 세례부터 승천까지 함께했던 사람 중에서 두 사람을 후보로 세우고, 기도로 하나님의 뜻을 구합니다. 제비를 뽑아 맛디아가 열두 번째 사도로 선출되는 이 과정은 초대교회가 얼마나 기도와 하나님의 인도하심을 중시했는지를 보여줍니다. 이렇게 열두 사도의 수가 회복되면서, 교회는 곧 임할 성령 강림과 세계 선교의 대장정을 준비하게 됩니다.', E'오늘의 핵심\n예수님의 승천 후 제자들은 다락방에 모여 한마음으로 기도하며 성령의 약속을 기다립니다. 이들의 연합된 기도는 교회 탄생의 초석이 되었습니다.\n\n묵상 질문\n1. 예수님이 주신 사명이 내 기대와 다를 때, 어떻게 순종할 수 있을까요?\n2. 다락방의 백이십 명처럼 한마음으로 기도하는 공동체를 경험해 보셨나요?\n3. 중요한 결정을 앞두고 기도로 하나님의 뜻을 구하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-19', E'베드로와 고넬료의 만남 (사도행전 2장)', E'사도행전 2장', E'예수님께서 승천하신 후 열흘째 되는 날, 오순절에 제자들이 한 곳에 모여 있을 때 놀라운 일이 일어났습니다. 하늘로부터 급하고 강한 바람 같은 소리가 들리더니 불의 혀처럼 갈라지는 것이 각 사람 위에 임했습니다. 그들이 성령의 충만함을 받자 각국의 언어로 하나님의 큰 일을 말하기 시작했습니다. 오순절 명절을 지키기 위해 천하 각국에서 예루살렘에 모인 유대인들은 갈릴리 출신 제자들이 자신들의 언어로 말하는 것을 듣고 크게 놀랐습니다.\n\n베드로는 이것이 요엘 선지자가 예언한 말씀의 성취임을 선포합니다. 하나님께서 말세에 모든 육체에 성령을 부어주시리라는 약속이 이루어진 것입니다. 베드로는 예수님의 십자가와 부활을 증거하며, 다윗의 예언을 통해 그리스도의 부활이 이미 구약에 예언되어 있었음을 설명합니다. 그리고 부활하신 예수님께서 하나님 우편에서 약속하신 성령을 받아 부어주신 것임을 선포합니다.\n\n베드로의 설교를 들은 사람들은 마음에 찔림을 받아 "우리가 어찌할꼬" 하며 묻습니다. 베드로는 회개하고 예수 그리스도의 이름으로 세례를 받으라고 권면합니다. 그날 삼천 명이나 되는 사람들이 말씀을 받고 세례를 받았습니다. 초대교회는 사도들의 가르침을 받으며 서로 교제하고, 떡을 떼며, 기도하기를 힘썼습니다. 그들은 모든 물건을 서로 통용하며 필요에 따라 나누어 주었고, 날마다 성전에 모이기를 힘쓰며 기쁨과 순전한 마음으로 하나님을 찬미했습니다. 이렇게 성령의 역사로 시작된 교회는 날마다 구원받는 사람이 더해지는 놀라운 부흥을 경험하게 됩니다.', E'오늘의 핵심\n오순절 성령 강림은 새로운 시대의 시작을 알리는 사건으로, 모든 민족과 언어의 장벽을 뛰어넘어 하나님의 구원이 온 세상에 선포되기 시작했습니다.\n\n묵상 질문\n1. 성령께서 각국의 언어로 복음을 전하게 하신 것은 하나님의 구원이 어떤 성격을 가지고 있음을 보여주나요?\n2. 베드로의 설교를 듣고 마음에 찔림을 받은 사람들처럼, 나도 회개와 결단이 필요한 부분이 있나요?\n3. 초대교회가 보여준 나눔과 교제의 모습을 오늘날 우리 공동체는 어떻게 실천할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-20', E'베드로와 고넬료의 만남 (사도행전 3장)', E'사도행전 3장', E'오순절 성령 강림 이후, 베드로와 요한은 오후 세 시 기도 시간에 맞춰 성전으로 올라갑니다. 유대인들에게 이 시간은 일상의 기도가 삶의 리듬이 되는 중요한 시각이었습니다. 바로 그 길목, 성전 미문에서 평생을 구걸로 연명해온 한 사람을 만나게 됩니다. 나면서부터 걷지 못했던 이 사람은 날마다 같은 자리에서 동전 몇 닢을 구하며 살아왔습니다.\n\n베드로는 그를 주목하여 보며 "은과 금은 내게 없거니와 내게 있는 이것을 네게 주노니 나사렛 예수 그리스도의 이름으로 일어나 걸으라"(행 3:6)고 선포합니다. 그 순간 기적이 일어납니다. 평생 한 번도 제대로 서본 적 없던 다리에 힘이 들어가고, 그는 뛰어 일어나 걷기도 하고 뛰기도 하며 하나님을 찬송합니다. 이 놀라운 광경은 성전에 모인 모든 사람들을 경악하게 만들었습니다.\n\n솔로몬 행각에 모여든 군중들 앞에서 베드로는 이 기적의 진정한 의미를 설명합니다. 이것은 사도들의 개인적 능력이나 경건함 때문이 아니라, 그들이 십자가에 못 박았던 바로 그 예수님의 이름에 있는 능력 때문이라고 증거합니다. 베드로는 그들이 거룩하고 의로운 이를 거부하고 살인자 바라바를 택한 일을 상기시키면서도, 이 모든 일이 하나님께서 선지자들을 통해 미리 말씀하신 계획 안에서 이루어진 것임을 밝힙니다.\n\n베드로의 설교는 정죄로 끝나지 않습니다. 그는 회개와 돌이킴을 통한 죄 사함의 길을 제시하며, 예수 그리스도를 통한 새로운 시대의 도래를 선포합니다. 미문의 거지가 일어나 걷게 된 것처럼, 이스라엘도 영적으로 일어나 새롭게 될 수 있다는 희망의 메시지를 전합니다.', E'오늘의 핵심\n예수님의 이름에는 평생의 절망을 순간의 기쁨으로 바꾸는 능력이 있으며, 이 능력은 회개하고 믿는 모든 이에게 열려 있습니다.\n\n묵상 질문\n1. 내 삶에서 ''은과 금''보다 더 귀한 예수님의 이름을 누군가에게 전할 준비가 되어 있나요?\n2. 하나님의 계획 안에서 내가 경험한 아픔이나 실패도 의미가 있다고 믿으시나요?\n3. 오늘 누군가에게 희망의 손을 내밀며 "일어나 걸으라" 말할 수 있는 용기를 구해보시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-21', E'베드로와 고넬료의 만남 (사도행전 4장)', E'사도행전 4장', E'성전 미문에서 일어난 치유의 기적은 예루살렘 전체를 뒤흔들었습니다. 종교 지도자들은 사도들이 예수의 부활을 전파하는 것을 막으려 했지만, 오히려 이 사건은 초대교회가 더욱 담대해지는 계기가 되었습니다.\n\n제사장들과 사두개인들은 사도들을 체포하여 공회 앞에 세웁니다. 그들이 가장 두려워한 것은 예수 안에 죽은 자의 부활이 있다는 가르침이었습니다. 사두개인들은 부활을 믿지 않았기에 이 메시지는 그들의 신학적 기반을 흔드는 것이었습니다. 그러나 하룻밤 사이에 믿는 자의 수가 오천 명에 이르렀다는 사실은 복음의 능력이 어떤 억압도 막을 수 없음을 보여줍니다.\n\n공회 앞에 선 베드로는 성령의 충만함 가운데 담대히 선포합니다. "너희가 십자가에 못 박고 하나님이 죽은 자 가운데서 살리신 나사렛 예수 그리스도의 이름으로 이 사람이 건강하게 되어 너희 앞에 섰느니라"(행 4:10). 한때 대제사장의 여종 앞에서도 두려워 떨었던 베드로가 이제는 최고 권력자들 앞에서 거침없이 복음을 전합니다. 성령의 능력이 연약한 인간을 변화시킨 것입니다.\n\n종교 지도자들은 베드로와 요한이 학문 없는 범인임을 알면서도 그들의 담대함에 놀랍니다. 더구나 치유받은 사람이 증거로 서 있었기에 할 말을 잃었습니다. 그들은 사도들을 위협하며 예수의 이름으로 말하지 말라고 명령하지만, 베드로와 요한은 "우리는 보고 들은 것을 말하지 아니할 수 없다"고 응답합니다.\n\n풀려난 사도들과 교회는 박해 앞에서 두려워하지 않고 오히려 더 큰 담대함을 구하며 기도합니다. 그들의 기도가 끝났을 때 모인 곳이 진동하며 성령의 충만함을 받습니다. 이 능력은 교회를 하나 되게 했고, 믿는 자들은 모든 물건을 서로 통용하며 가난한 자가 없도록 돌보았습니다. 바나바처럼 자기 소유를 팔아 나누는 아름다운 헌신이 일어났습니다.\n\n초대교회는 외적인 박해와 위협 속에서도 성령의 능력으로 더욱 강건해졌습니다. 그들이 의지한 것은 인간의 권세가 아니라 부활하신 예수 그리스도의 이름이었습니다.', E'오늘의 핵심\n박해와 위협 앞에서도 성령 충만한 사도들은 담대히 복음을 전했고, 초대교회는 한마음으로 연합하여 사랑의 공동체를 이루었습니다.\n\n묵상 질문\n1. 내가 예수님을 증거하는 데 있어서 두려워하는 ''공회''는 무엇인가요?\n2. "보고 들은 것을 말하지 않을 수 없다"는 베드로의 고백이 내 삶에서는 어떻게 나타나고 있나요?\n3. 초대교회의 나눔과 헌신을 보며, 오늘 내가 실천할 수 있는 사랑의 행동은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-22', E'베드로와 고넬료의 만남 (사도행전 5장)', E'사도행전 5장', E'초대교회에는 성령의 놀라운 역사와 함께 인간의 연약함도 드러났습니다. 아나니아와 삽비라는 소유를 팔아 헌금하면서도 그 값의 일부를 감추었습니다. 그들의 문제는 단순히 재산의 일부를 남겨둔 것이 아니라, 전부를 바친 것처럼 속이려 한 것이었습니다. 베드로는 이것이 사람에게 거짓말한 것이 아니라 하나님께 거짓말한 것임을 지적합니다. 이 사건으로 아나니아와 삽비라가 죽음에 이르자 온 교회가 큰 두려움에 사로잡혔습니다. 이는 하나님께서 거룩한 공동체를 세워가시는 과정에서 진실함의 중요성을 가르치신 엄중한 교훈이었습니다.\n\n한편 사도들을 통한 표적과 기사는 계속되었고, 믿는 자들의 수는 더욱 늘어났습니다. 병든 사람들이 베드로의 그림자라도 닿기를 바라며 거리에 누워있을 정도로 하나님의 능력이 크게 나타났습니다. 이에 위기감을 느낀 대제사장과 사두개인들은 사도들을 잡아 옥에 가두었지만, 주의 사자가 밤에 옥문을 열어 그들을 이끌어내며 "가서 성전에서 이 생명의 말씀을 다 백성에게 말하라"고 명했습니다. \n\n공회 앞에 선 베드로는 "사람보다 하나님께 순종하는 것이 마땅하니라"고 선포하며, 십자가에 달려 죽으신 예수님을 하나님께서 살리시고 임금과 구주로 삼으셨음을 담대히 증거했습니다. 율법교사 가말리엘의 지혜로운 조언으로 사도들은 채찍질을 당한 후 풀려났지만, 그들은 오히려 그리스도의 이름을 위해 고난받는 것을 기뻐하며 날마다 예수가 그리스도이심을 전파하기를 멈추지 않았습니다. 초대교회는 이렇게 핍박 속에서도 복음의 능력으로 전진해 나갔습니다.', E'오늘의 핵심\n하나님께서는 거룩한 교회 공동체를 세워가시면서 진실함을 요구하시고, 핍박 속에서도 복음을 담대히 전하는 사도들을 통해 하나님 나라를 확장시켜 가십니다.\n\n묵상 질문\n1. 아나니아와 삽비라의 이야기를 통해 나는 하나님 앞에서 어떤 가면을 벗어야 할까요?\n2. "사람보다 하나님께 순종하는 것이 마땅하다"는 베드로의 고백이 내 삶에서는 어떻게 실천될 수 있을까요?\n3. 그리스도를 위한 고난을 기뻐했던 사도들처럼, 오늘 내가 기쁨으로 감당할 수 있는 희생은 무엇일까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-23', E'베드로와 고넬료의 만남 (사도행전 6장)', E'사도행전 6장', E'초기교회가 성장하면서 예상치 못한 문제가 발생했습니다. 헬라파 유대인들이 자신들의 과부들이 매일의 구제에서 소외되고 있다고 히브리파 사람들을 원망하기 시작한 것입니다. 교회의 양적 성장이 가져온 첫 번째 내부 갈등이었습니다. 이는 단순한 행정적 실수가 아니라 공동체의 본질을 시험하는 중요한 순간이었습니다.\n\n사도들의 대응은 지혜로웠습니다. 그들은 문제를 회피하거나 권위로 누르지 않고, 공동체와 함께 해결책을 모색했습니다. "성령과 지혜가 충만하여 칭찬 받는 사람 일곱을 택하라"(행 6:3)는 제안을 통해 새로운 리더십 구조를 만들어냈습니다. 선출된 일곱 명의 이름이 모두 헬라식인 것으로 보아, 교회는 소외된 그룹의 필요를 적극적으로 배려했음을 알 수 있습니다.\n\n이 사건을 통해 초기교회는 더욱 성숙해졌습니다. 사도들은 기도와 말씀 사역에 전념할 수 있게 되었고, 새로운 일꾼들은 구제 사역을 전문적으로 감당하게 되었습니다. 그 결과 "하나님의 말씀이 점점 왕성하여" 제자의 수가 더욱 늘어났고, 놀랍게도 많은 제사장들까지 복음을 받아들이게 되었습니다.\n\n특히 주목할 것은 스데반의 사역입니다. 구제를 위해 세워진 그가 은혜와 권능이 충만하여 큰 기사와 표적을 행했다는 것은, 하나님께서 주신 은사가 특정 역할에 제한되지 않음을 보여줍니다. 그러나 복음의 능력이 나타날수록 반대도 거세졌습니다. 자유민들의 회당에서 온 사람들이 스데반과 논쟁했지만, 그의 지혜와 성령의 말씀을 당해낼 수 없자 거짓 증인을 세워 모함하기에 이르렀습니다.\n\n공회 앞에 선 스데반의 얼굴이 천사의 얼굴과 같았다는 묘사는 의미심장합니다. 거짓 고소와 죽음의 위협 앞에서도 그의 얼굴에서 빛나는 하나님의 영광은, 진리가 박해를 받을 때 오히려 더욱 분명하게 드러남을 보여주는 증거였습니다. 교회는 내부의 갈등을 지혜롭게 해결하고, 외부의 박해를 담대히 맞서며 계속해서 성장해 나갔습니다.', E'오늘의 핵심\n초기교회는 내부 갈등을 성령의 지혜로 해결하며 더욱 견고한 공동체로 성장했고, 박해 속에서도 복음의 능력은 더욱 분명하게 나타났습니다.\n\n묵상 질문\n1. 우리 공동체 안에서 소외되고 있는 사람들의 필요를 어떻게 채울 수 있을까요?\n2. 문제 해결을 위해 기도와 성령의 지혜를 구하고 있나요, 아니면 인간적 방법에만 의존하고 있나요?\n3. 반대와 오해를 받을 때에도 스데반처럼 하나님의 영광을 나타낼 수 있는 믿음이 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-25', E'베드로와 고넬료의 만남 (사도행전 7장)', E'사도행전 7장', E'스데반이 산헤드린 공회 앞에 섰습니다. 그는 거짓 증인들의 고소를 받아 재판받는 자리에서 놀라운 설교를 시작합니다. 스데반의 설교는 이스라엘 역사를 관통하는 하나님의 구원 이야기였습니다. 아브라함부터 시작하여 이삭, 야곱, 요셉, 모세에 이르기까지 하나님께서 어떻게 자기 백성을 인도하셨는지를 차분하게 풀어냅니다.\n\n스데반이 특별히 강조한 것은 하나님의 역사하심이 특정한 장소에 매이지 않는다는 점이었습니다. 아브라함은 메소포타미아에서 부르심을 받았고, 요셉은 애굽에서 하나님과 함께했으며, 모세는 미디안 광야에서 하나님을 만났습니다. "지극히 높으신 이는 손으로 지은 곳에 계시지 아니하시나니"(행 7:48)라는 선언은 성전 중심의 종교 지도자들에게는 충격적인 메시지였습니다.\n\n더 나아가 스데반은 이스라엘 백성이 역사 속에서 반복해온 불순종의 패턴을 지적합니다. 하나님께서 보내신 지도자들을 거부하고, 우상을 만들어 섬기며, 성령을 거역해온 조상들의 모습은 바로 지금 예수님을 십자가에 못 박고 그분의 제자들을 박해하는 종교 지도자들의 모습과 다르지 않았습니다.\n\n스데반의 설교는 단순한 역사 강의가 아니었습니다. 그것은 하나님께서 예수 그리스도를 통해 이루신 구원의 완성을 증거하는 복음 선포였고, 동시에 그 복음을 거부하는 자들에 대한 선지자적 책망이었습니다. 비록 이 담대한 설교가 그를 순교의 자리로 이끌었지만, 스데반은 끝까지 하나님의 영광을 바라보며 증인의 사명을 완수했습니다.', E'오늘의 핵심\n스데반은 이스라엘의 역사를 통해 하나님의 구원 계획이 어떻게 예수 그리스도 안에서 성취되었는지를 증거하며, 복음을 거부하는 종교 지도자들의 완고함을 책망합니다.\n\n묵상 질문\n1. 하나님은 특정한 장소나 건물에 갇히지 않으시는 분이신가요?\n2. 내가 하나님의 새로운 역사하심을 거부하고 있는 영역은 없을까요?\n3. 복음의 진리를 위해 담대히 증거해야 할 때 나는 어떤 자세를 취하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-26', E'베드로와 고넬료의 만남 (사도행전 8장)', E'사도행전 8장', E'스데반의 순교 직후, 예루살렘 교회에 큰 박해가 시작되었습니다. 사울이 앞장서서 교회를 잔멸하려 했고, 각 집에 들어가 남녀를 끌어다가 옥에 넘길 정도로 박해는 격렬했습니다. 그 결과 사도들을 제외한 대부분의 성도들이 유대와 사마리아 모든 땅으로 흩어지게 되었습니다. 그런데 놀라운 것은 이 흩어진 사람들이 두루 다니며 복음의 말씀을 전했다는 사실입니다. 박해로 인한 흩어짐이 오히려 복음 전파의 통로가 된 것입니다.\n\n특별히 빌립은 사마리아 성에 내려가 그리스도를 전파했습니다. 유대인들이 멸시하던 사마리아인들에게 복음이 전해지기 시작한 것입니다. 빌립의 사역을 통해 많은 표적이 나타났고, 더러운 귀신들이 쫓겨나고 중풍병자와 못 걷는 사람들이 치유되었습니다. 그 결과 "그 성에 큰 기쁨이 있더라"(행 8:8)고 성경은 기록합니다. 마술사 시몬까지도 빌립의 전도를 듣고 믿어 세례를 받았습니다. 하지만 시몬은 성령의 은사를 돈으로 사려 했고, 베드로에게 엄중한 책망을 받게 됩니다. 이는 하나님의 은혜를 인간적인 방법으로 취하려는 잘못된 신앙의 모습을 보여줍니다.\n\n한편 빌립은 성령의 인도하심을 따라 광야 길에서 에티오피아 내시를 만나게 됩니다. 예배하러 예루살렘에 왔다가 돌아가던 이 내시는 이사야서를 읽고 있었지만 그 의미를 깨닫지 못하고 있었습니다. 빌립은 그가 읽던 이사야서 53장의 고난받는 종에 관한 말씀으로부터 시작하여 예수 그리스도의 복음을 전했습니다. 내시는 즉시 믿고 세례를 받았으며, 기쁘게 길을 갔습니다. 이렇게 복음은 유대와 사마리아를 넘어 이방 땅까지 전파되기 시작했습니다. 박해로 인한 흩어짐이 도리어 하나님 나라 확장의 도구가 되었던 것입니다.', E'오늘의 핵심\n예루살렘 교회에 임한 큰 박해는 성도들을 흩어지게 했지만, 오히려 이를 통해 복음이 사마리아와 이방 땅까지 전파되는 놀라운 역사가 일어났습니다.\n\n묵상 질문\n1. 내 삶의 어려움과 흩어짐이 오히려 복음 전파의 기회가 될 수 있다고 믿으시나요?\n2. 빌립처럼 성령의 인도하심에 즉시 순종할 준비가 되어 있나요?\n3. 복음을 전하기 위해 내가 넘어야 할 편견의 장벽은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-27', E'베드로와 고넬료의 만남 (사도행전 9장)', E'사도행전 9장', E'예루살렘에서 스데반의 순교 이후, 기독교 박해의 최전선에 섰던 사울이 다메섹으로 향하는 길에 오릅니다. 대제사장의 공문을 받아 그리스도인들을 잡아오려는 그의 발걸음에는 살기가 가득했습니다. 그런데 다메섹 성에 가까이 이르렀을 때, 하늘로부터 강렬한 빛이 그를 둘러 비춥니다. 땅에 엎드러진 사울에게 부활하신 예수께서 직접 말씀하십니다. "사울아 사울아 네가 어찌하여 나를 박해하느냐"(행 9:4). 교회를 박해하는 것이 곧 예수님을 박해하는 것임을 깨닫게 하신 것입니다.\n\n이 만남은 사울의 인생을 완전히 뒤바꾸어 놓습니다. 눈이 멀어 사람의 손에 이끌려 다메섹으로 들어간 사울은 사흘 동안 보지도 못하고 먹지도 마시지도 않으며 깊은 영적 전환의 시간을 보냅니다. 하나님께서는 아나니아라는 제자를 통해 사울의 눈을 다시 뜨게 하시고, 그를 이방인과 왕들과 이스라엘 자손들에게 복음을 전할 그릇으로 택하셨음을 알려주십니다.\n\n눈을 뜬 사울은 즉시 회당에서 예수가 하나님의 아들이심을 전파하기 시작합니다. 박해자에서 전도자로의 극적인 변화는 다메섹의 유대인들을 당황하게 만들었고, 급기야 그들은 사울을 죽이려는 음모를 꾸밉니다. 밤중에 광주리를 타고 성벽을 넘어 탈출한 사울은 예루살렘으로 가지만, 그곳의 제자들조차 그의 회심을 믿지 못합니다. 이때 바나바가 나서서 사울을 사도들에게 인도하고 그의 진정성을 보증해 줍니다. \n\n한편 베드로는 각 지역을 순회하며 복음을 전하고 병자들을 고치는 사역을 계속합니다. 룻다에서는 8년 된 중풍병자 애니아를 고치고, 욥바에서는 죽은 도르가를 살려냅니다. 이러한 표적들을 통해 많은 사람들이 주께로 돌아오게 됩니다. 하나님께서는 박해자를 전도자로 바꾸시고, 죽은 자를 살리시며, 교회의 평안과 부흥을 허락하십니다.', E'오늘의 핵심\n부활하신 예수님은 교회의 최대 박해자였던 사울을 직접 만나 회심시키시고, 이방인의 사도로 부르십니다. 하나님의 은혜는 가장 완고한 대적자도 복음의 증인으로 변화시킬 수 있습니다.\n\n묵상 질문\n1. 내 삶에서 하나님을 만나 완전히 변화된 경험이 있나요?\n2. 나를 미워하거나 반대하는 사람도 하나님께서 변화시키실 수 있다고 믿나요?\n3. 바나바처럼 회심한 사람을 따뜻하게 받아주고 다리를 놓아주는 역할을 하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-28', E'베드로와 고넬료의 만남 (사도행전 10장)', E'사도행전 10장', E'가이사랴에 주둔한 로마 백부장 고넬료는 이방인이었지만 하나님을 경외하는 경건한 사람이었습니다. 그가 기도하던 중 하나님의 사자가 나타나 베드로를 청하라는 지시를 받습니다. 동시에 욥바에서 기도하던 베드로에게도 하늘에서 내려온 보자기에 담긴 각종 짐승들을 보는 환상이 주어집니다. 유대인으로서 부정한 것을 먹을 수 없다고 거부하는 베드로에게 "하나님께서 깨끗하게 하신 것을 네가 속되다 하지 말라"(행 10:15)는 음성이 들립니다.\n\n이 환상의 의미를 깨닫지 못하던 베드로에게 고넬료가 보낸 사람들이 도착합니다. 성령의 인도하심을 따라 베드로는 그들과 함께 가이사랴로 향합니다. 로마의 백부장이 유대인 앞에 엎드려 절하는 놀라운 광경이 펼쳐집니다. 베드로는 비로소 깨닫습니다. 하나님께서는 사람의 외모를 보지 않으시고, 각 나라 중 하나님을 경외하며 의를 행하는 사람은 누구든지 받으신다는 것을 말입니다.\n\n베드로가 예수 그리스도의 복음을 전할 때, 놀라운 일이 일어납니다. 성령께서 말씀을 듣는 모든 이방인들에게 임하신 것입니다. 할례받은 유대인 신자들은 이방인들이 방언을 말하며 하나님을 높이는 것을 보고 놀랐습니다. 이것은 오순절 성령 강림이 이방인에게도 동일하게 일어난 것입니다. 베드로는 즉시 그들에게 세례를 베풀도록 명합니다.\n\n하나님께서는 베드로와 고넬료의 만남을 통해 구원의 문이 모든 민족에게 열렸음을 선포하십니다. 유대인의 선민의식과 이방인을 향한 편견의 장벽이 성령의 역사로 무너집니다. 교회는 이제 민족과 문화의 경계를 넘어 하나님 나라의 보편성을 깨닫게 되었습니다.', E'오늘의 핵심\n하나님께서는 베드로의 환상과 고넬료와의 만남을 통해 복음이 모든 민족을 위한 것임을 선포하시고, 성령의 은사로 이를 확증하십니다.\n\n묵상 질문\n1. 내가 가진 신앙의 편견이나 선입견은 무엇이며, 하나님께서 이를 어떻게 깨뜨리기 원하실까요?\n2. 고넬료처럼 하나님을 간절히 찾는 사람들에게 복음을 전할 준비가 되어 있나요?\n3. 성령께서는 민족과 문화의 장벽을 넘어 역사하시는데, 나는 어떤 열린 마음으로 하나님의 일하심에 동참할 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-29', E'베드로와 고넬료의 만남 (사도행전 11장)', E'사도행전 11장', E'초대교회 역사의 중요한 전환점이 사도행전 11장에 기록되어 있습니다. 베드로가 이방인 고넬료의 집을 방문하고 그들에게 세례를 베푼 소식이 예루살렘에 전해지자, 할례받은 유대인 신자들이 베드로를 비난합니다. 그들에게는 이방인과 함께 먹는다는 것이 율법을 어기는 심각한 일이었기 때문입니다. 베드로는 차분히 자신이 경험한 환상과 성령의 역사를 차례대로 설명합니다. 하늘에서 내려온 보자기에 담긴 부정한 짐승들, 그리고 "하나님이 깨끗하게 하신 것을 네가 속되다 하지 말라"는 음성이 세 번이나 반복되었음을 증언합니다.\n\n베드로의 설명 중 가장 결정적인 부분은 이방인들에게도 성령이 임하셨다는 사실입니다. 오순절에 유대인들이 받았던 것과 동일한 성령의 은사를 이방인들도 받았다는 것은 하나님께서 그들을 동등하게 받아주셨다는 명백한 증거였습니다. 이 증언을 들은 예루살렘 교회는 침묵했다가 마침내 하나님께 영광을 돌리며 "하나님께서 이방인에게도 생명 얻는 회개를 주셨도다"라고 고백합니다. 이는 교회사의 획기적인 순간으로, 복음이 유대인의 울타리를 넘어 온 세상으로 확산되는 문이 공식적으로 열린 것입니다.\n\n한편 스데반의 순교로 흩어진 신자들 중 일부는 안디옥에 이르러 헬라인들에게도 복음을 전했고, 놀랍게도 수많은 사람이 주께 돌아왔습니다. 예루살렘 교회는 바나바를 파송하여 이 일을 살피게 했는데, 바나바는 그곳에서 하나님의 은혜를 목격하고 크게 기뻐했습니다. 더 나아가 그는 다소에 있던 사울을 찾아가 안디옥으로 데려와 함께 사역했습니다. 이렇게 안디옥 교회는 이방인 선교의 전진기지가 되었고, 제자들이 처음으로 ''그리스도인''이라 불리게 된 역사적인 장소가 되었습니다. 교회는 민족과 문화의 장벽을 넘어 그리스도 안에서 하나 되는 공동체로 성장해 나갔습니다.', E'오늘의 핵심\n하나님께서는 성령의 역사를 통해 이방인도 구원의 대상임을 분명히 보여주셨고, 초대교회는 이를 인정하며 복음의 보편성을 받아들였습니다.\n\n묵상 질문\n1. 나에게도 깨뜨려야 할 편견의 장벽이 있다면 무엇인가요?\n2. 하나님의 은혜가 내 생각보다 훨씬 넓고 깊다는 것을 경험한 적이 있나요?\n3. 복음 안에서 ''다름''을 인정하고 함께 하나 되는 공동체를 어떻게 만들어갈 수 있을까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-06-30', E'베드로와 고넬료의 만남 (사도행전 12장)', E'사도행전 12장', E'초대교회를 향한 핍박의 손길이 더욱 거세지고 있었습니다. 헤롯 아그립바 1세가 교회를 탄압하기 시작하면서 요한의 형제 야고보를 칼로 죽였고, 이것이 유대인들에게 호응을 얻자 베드로마저 체포했습니다. 무교절 기간이었기에 헤롯은 유월절이 끝난 후 베드로를 백성 앞에서 처형하려고 계획했습니다. 네 명씩 네 패의 군인들이 삼엄하게 베드로를 지키고 있었지만, 교회는 그를 위해 간절히 기도했습니다.\n\n베드로가 처형되기 전날 밤, 놀라운 일이 일어났습니다. 주의 천사가 나타나 쇠사슬에 묶여 있던 베드로를 깨우고, 삼엄한 경비를 뚫고 그를 감옥 밖으로 인도했습니다. 베드로는 처음에 이것이 환상인 줄 알았으나, 거리로 나왔을 때 비로소 하나님께서 자신을 구원하신 것을 깨달았습니다. 그는 곧바로 마가 요한의 어머니 마리아의 집으로 갔는데, 그곳에서는 많은 성도들이 모여 기도하고 있었습니다. \n\n흥미롭게도 간절히 기도하던 그들은 정작 베드로가 문을 두드렸을 때 믿지 못했습니다. 로데라는 여종이 베드로의 음성을 알아듣고 기뻐하며 전했지만, 사람들은 그녀가 미쳤다고 여겼습니다. 이는 우리의 기도 생활을 돌아보게 합니다. 간절히 기도하면서도 정작 응답이 왔을 때 믿지 못하는 우리의 연약한 믿음을 보여줍니다.\n\n한편 베드로를 잃어버린 헤롯은 파수꾼들을 처형하고 가이사랴로 내려갔습니다. 그곳에서 두로와 시돈 사람들 앞에서 연설할 때, 백성들이 "이것은 신의 소리요 사람의 소리가 아니라"고 외쳤습니다. 헤롯이 이 영광을 하나님께 돌리지 않자, 주의 사자가 그를 쳐서 벌레에게 먹혀 죽게 했습니다. 교회를 핍박하던 헤롯은 비참한 최후를 맞았지만, "하나님의 말씀은 흥왕하여 더하더라"(행 12:24)고 성경은 기록합니다. 하나님의 나라는 어떤 박해와 위협 속에서도 전진하며 확장되어 갑니다.', E'오늘의 핵심\n하나님께서는 기도하는 교회를 통해 일하시며, 교회를 핍박하는 자들의 교만을 꺾으시고 복음이 계속 전파되도록 역사하십니다.\n\n묵상 질문\n1. 내가 간절히 기도하면서도 정작 응답을 의심하거나 놓친 적은 없나요?\n2. 어려운 상황 속에서도 함께 모여 기도하는 공동체의 힘을 경험해 보셨나요?\n3. 헤롯처럼 하나님께 돌려야 할 영광을 가로채려는 교만한 마음은 없는지 돌아볼까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-07-02', E'진리 안에서 자유하라', E'갈라디아서 3장', E'자유를 위한 대선언이라고 불리는 갈라디아서는 갈라디아 지방에 있는 여러 교회들에게 바울이 보낸 편지입니다. 바울이 모진 고생을 참아낸 것도, 자신의 모든 기득권을 포기한 것도, 긴 여행길을 마다하지 않았던 것도, 모두 복음을 전해야 한다는 사명감 때문이었습니다. 그 같은 바울의 헌신을 바탕으로 세워진 갈라디아 교회로부터 들려온 소식은 바울이 전한 복음 외에 다른 복음을 전하는 이들이 있다는 것이었습니다. 뿐만 아니라 그 거짓 진리에 흔들리는 사람이 적지 않다는 것입니다. 바울이 전하지 않은 복음이란, 예수님을 믿는 모든 사람들이 유대인의 규례대로 할례를 받아야만 구원을 얻을 수 있다는 주장이었습니다. 즉 율법을 지켜야 구원을 받는다는 것입니다.\n이 소식을 들은 바울은 갈라디아서를 통해 거짓 복음에 흔들린 갈라디아 교인들을 책망합니다. 바울은 자신의 주장 곧 할례와 상관없이 오직 예수님을 믿는 믿음으로 구원받는다는 주장을 조금도 굽히지 않습니다. 그러면서 자신이 진리를 지키기 위해 힘쓰고 있다고 강력하게 호소합니다. 할례나 율법이 아니라 오직 믿음으로써만 의롭게 된다는 진리를 지키기 위해 바울이 끝까지 싸우고 있습니다.', E'오늘의 핵심\n거짓 진리에 흔들리는 갈라디아 교인들에게 바울은 율법의 행위로가 아니라 오직 믿음 안에서 자유를 얻게 됨을 강조합니다.\n\n묵상 질문\n1. 예수님 믿음만으로도 충분하다고 하신 하나님의 마음은 무엇일까요?\n2. 율법 준수 대신 그리스도의 은혜만으로 살아가는 것이 나에게는 어떤 의미일까요?\n3. 거짓 진리에 흔들리지 않고 오직 예수님을 붙잡겠다고 결단하시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-07-03', E'성령의 열매를 맺으라 (갈라디아서 4장)', E'갈라디아서 4장', E'갈라디아 교회는 바울이 전한 복음을 받아들였지만, 유대주의자들의 영향으로 다시 율법주의로 돌아가려는 위기에 처해 있었습니다. 바울은 이런 상황에서 율법과 복음의 관계를 상속의 비유로 설명합니다. 어린 상속자가 성년이 되기 전까지는 종과 다름없이 후견인의 감독 아래 있듯이, 우리도 그리스도께서 오시기 전에는 율법의 감독 아래 있었다는 것입니다.\n\n그러나 때가 차매 하나님께서는 그 아들을 보내셨습니다. 여자에게서 나시고 율법 아래 나신 그리스도는 율법 아래 있는 자들을 속량하시고 우리에게 아들의 명분을 주셨습니다. 이제 우리는 더 이상 종이 아닌 하나님의 자녀가 되었고, 성령께서 우리 마음에 오셔서 하나님을 "아빠 아버지"라 부르게 하셨습니다. 이것이 복음이 가져다준 놀라운 신분의 변화입니다.\n\n바울은 갈라디아 교인들에게 묻습니다. 하나님을 알고 더욱이 하나님께 알려진 자가 되었는데, 왜 다시 초등학문으로 돌아가려 하느냐고 말입니다. 날과 달과 절기를 지키는 것으로 구원을 얻으려는 시도는 약속의 자녀가 아닌 종의 자녀로 돌아가는 것입니다. 하갈과 사라의 비유를 통해 바울은 율법은 종을 낳지만 복음은 자유를 낳는다는 진리를 보여줍니다. 우리는 하갈의 자녀가 아닌 사라의 자녀, 곧 약속의 자녀입니다. 그러므로 우리는 종의 멍에를 다시 메지 말고, 그리스도께서 주신 자유 안에 굳건히 서야 합니다.', E'오늘의 핵심\n하나님께서는 때가 차매 그 아들을 보내어 우리를 종의 신분에서 자녀의 신분으로 옮기셨고, 이제 우리는 약속의 자녀로서 진정한 자유를 누리게 되었습니다.\n\n묵상 질문\n1. 나는 여전히 종처럼 하나님을 섬기고 있지는 않은가요? 아들의 영이 내 안에 계심을 경험하고 있나요?\n2. 내가 붙잡고 있는 ''초등학문''은 무엇인가요? 율법주의적 신앙에서 벗어나 은혜의 복음 안에 있나요?\n3. 약속의 자녀로서 누리는 자유를 어떻게 사용하고 있나요? 그 자유가 사랑으로 열매 맺고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-07-04', E'성령의 열매를 맺으라 (갈라디아서 5장)', E'갈라디아서 5장', E'그리스도께서 주신 자유는 단순히 율법의 굴레에서 벗어난 것 이상의 의미를 담고 있습니다. 바울은 갈라디아 교인들에게 "그리스도께서 우리를 자유롭게 하려고 자유를 주셨으니 그러므로 굳건하게 서서 다시는 종의 멍에를 메지 말라"(갈 5:1)고 강권합니다. 할례와 같은 율법적 행위로 의를 얻으려는 시도는 오히려 그리스도의 은혜에서 떨어지는 결과를 낳습니다. 참된 의는 성령으로 믿음을 따라 소망 가운데 기다리는 것입니다.\n\n바울이 제시하는 자유의 본질은 역설적입니다. 자유를 얻었으나 그것을 육체의 기회로 삼지 말고 오히려 사랑으로 서로 종 노릇하라는 것입니다. 이는 율법의 완성이 바로 이웃 사랑에 있기 때문입니다. 성령을 따라 행하는 삶은 육체의 소욕과 대적하며 싸우는 영적 전쟁입니다. 육체의 일들은 분명히 드러나는데, 음행과 우상숭배, 분쟁과 시기 등 공동체를 파괴하는 모든 악행들이 여기에 속합니다.\n\n반면 성령의 열매는 사랑과 희락과 화평으로 시작하여 온유와 절제로 마무리됩니다. 이 아홉 가지 성령의 열매는 그리스도인의 성품이 어떻게 변화되어야 하는지를 보여줍니다. 그리스도 예수께 속한 사람들은 이미 육체와 함께 그 정욕과 탐심을 십자가에 못 박았습니다. 이제 성령으로 살아가는 우리는 헛된 영광을 구하지 않고 서로를 세워주는 삶을 살아야 합니다. 참된 자유는 방종이 아니라 사랑 안에서 서로를 섬기는 것입니다.', E'오늘의 핵심\n그리스도께서 주신 자유는 육체의 방종이 아니라 사랑으로 서로를 섬기며 성령의 아름다운 열매를 맺는 삶으로 나타납니다.\n\n묵상 질문\n1. 나는 그리스도의 자유를 누리면서도 여전히 어떤 종의 멍에를 메고 있지는 않은가요?\n2. 육체의 소욕과 성령의 인도하심 사이에서 어떤 영적 싸움을 경험하고 있나요?\n3. 성령의 아홉 가지 열매 중에서 특별히 더 맺고 싶은 열매는 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-07-05', E'성령의 열매를 맺으라 (갈라디아서 6장)', E'갈라디아서 6장', E'갈라디아서 6장은 바울이 그리스도인의 공동체 생활과 복음의 본질을 마지막으로 강조하는 부분입니다. 바울은 먼저 형제가 범죄에 빠졌을 때 어떻게 대해야 하는지를 가르칩니다. "신령한 너희는 온유한 심령으로 그러한 자를 바로잡고"(갈 6:1)라는 말씀은 영적 교만이 아닌 겸손한 사랑으로 서로를 돌보라는 것입니다. 이어서 바울은 "너희가 짐을 서로 지라"고 권면하며, 이것이 곧 그리스도의 법을 성취하는 길임을 밝힙니다. 율법의 무거운 짐에서 해방된 그리스도인들은 이제 사랑으로 서로의 짐을 나누어 지는 새로운 공동체를 이루어야 합니다.\n\n바울은 영적 심기와 거두기의 원리를 통해 그리스도인의 삶의 방향을 제시합니다. 육체를 위해 심는 자는 썩어질 것을 거두지만, 성령을 위해 심는 자는 영생을 거둔다는 이 가르침은 우리의 일상적 선택이 얼마나 중요한지를 보여줍니다. 특히 "우리가 선을 행하되 낙심하지 말지니"라는 권면은 당장 열매가 보이지 않더라도 포기하지 말고 꾸준히 선을 행하라는 격려입니다.\n\n편지의 마지막 부분에서 바울은 자신의 큰 글씨체로 직접 쓰면서 복음의 핵심을 다시 한 번 강조합니다. 할례를 강요하는 자들의 위선을 폭로하면서, 바울은 "우리 주 예수 그리스도의 십자가 외에 결코 자랑할 것이 없으니"라고 선언합니다. 이는 갈라디아서 전체를 관통하는 메시지입니다. 율법의 행위가 아닌 오직 그리스도의 십자가만이 우리의 구원이며 자랑입니다. 바울은 자신의 몸에 지닌 예수의 흔적을 언급하며 편지를 마무리합니다. 이는 복음을 위해 받은 고난의 흔적들로서, 그가 전하는 메시지의 진정성을 보여줍니다.', E'오늘의 핵심\n바울은 그리스도의 십자가로 새로워진 공동체가 온유함과 사랑으로 서로의 짐을 지며, 성령을 따라 선을 심는 삶을 살아야 함을 가르칩니다.\n\n묵상 질문\n1. 형제자매가 넘어졌을 때 정죄하기보다 온유한 심령으로 바로잡아 주신 경험이 있으신가요?\n2. 오늘 내가 심고 있는 것은 육체를 위한 것인가요, 성령을 위한 것인가요?\n3. 그리스도의 십자가 외에 자랑하고 싶은 다른 것들이 내 마음속에 있지는 않은가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-07-06', E'십자가의 도 (고린도전서 1장)', E'고린도전서 1장', E'바울은 고린도에 있는 성도들에게 편지를 시작하면서 먼저 감사를 표현합니다. 복음을 받아들인 후 그들이 모든 언변과 지식에 풍족하게 되었고, 그리스도의 증거가 견고하게 되어 모든 은사에 부족함이 없다고 칭찬합니다. 그러나 곧이어 바울은 글로에의 집 편으로 들려온 안타까운 소식을 언급합니다. 고린도 교회 안에 분쟁이 일어나 성도들이 각각 "나는 바울에게, 나는 아볼로에게, 나는 게바에게, 나는 그리스도에게 속한 자라"고 주장하며 파벌을 만들고 있다는 것이었습니다.\n\n바울은 이러한 분열의 어리석음을 지적합니다. 그리스도께서 나뉘실 수 없으며, 바울이나 아볼로가 십자가에 못 박힌 것도 아닌데 어찌 사람을 따라 분파를 만들 수 있느냐고 반문합니다. 바울은 자신이 세례를 베푼 사람이 몇 명 되지 않음을 감사한다고 말하는데, 이는 누구도 바울의 이름으로 세례받았다고 주장하며 파당을 만들지 못하게 하려는 의도였습니다.\n\n이어서 바울은 복음의 본질로 돌아갑니다. "십자가의 도가 멸망하는 자들에게는 미련한 것이요 구원을 받는 우리에게는 하나님의 능력이라"(18절)는 선포를 통해, 인간의 지혜가 아닌 하나님의 지혜에 주목하게 합니다. 유대인들은 표적을 구하고 헬라인들은 지혜를 찾지만, 복음은 십자가에 못 박힌 그리스도를 전하는 것입니다. 세상의 눈으로는 어리석고 약해 보이는 이 메시지가 바로 하나님의 능력이요 지혜라는 역설을 제시합니다.\n\n하나님께서는 세상의 미련한 것들을 택하여 지혜 있는 자들을 부끄럽게 하시고, 약한 것들을 택하여 강한 것들을 부끄럽게 하십니다. 이는 어떤 육체도 하나님 앞에서 자랑하지 못하게 하려는 것입니다. 고린도 교회가 사람을 따라 분파를 만드는 것은 결국 인간적 자랑과 교만에서 비롯된 것임을 암시합니다. 참된 지혜와 의로움과 거룩함과 구원은 오직 그리스도 예수 안에서만 발견되며, 우리의 자랑은 오직 주 안에서만 이루어져야 합니다.', E'오늘의 핵심\n바울은 고린도 교회의 분열 문제를 지적하며, 인간의 지혜가 아닌 십자가의 도 안에서 하나 되어야 함을 가르칩니다. 하나님의 지혜는 세상의 지혜를 뒤집는 역설적 능력입니다.\n\n묵상 질문\n1. 내가 따르고 있는 것이 그리스도인가, 아니면 사람의 이름인가요?\n2. 세상이 미련하다고 여기는 십자가의 도가 내게는 어떤 능력이 되고 있나요?\n3. 하나님 앞에서 내가 자랑하던 것들을 내려놓고 오직 주 안에서 자랑할 수 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-07-07', E'십자가의 도 (고린도전서 2장)', E'고린도전서 2장', E'바울은 고린도 교회에 처음 복음을 전할 때 철저히 자신을 낮추었던 경험을 상기시킵니다. 당시 고린도는 헬라 철학과 수사학이 발달한 도시였고, 사람들은 말재주와 지혜로운 논증을 높이 평가했습니다. 그러나 바울은 그런 "말과 지혜의 아름다운 것"으로 복음을 전하지 않았다고 고백합니다. 오히려 그는 약하고 두려워하며 심히 떨면서 고린도 사람들 앞에 섰습니다. 이는 바울이 인간적인 능력을 의지하지 않고 오직 하나님의 능력만을 의지했음을 보여줍니다.\n\n바울이 전한 메시지의 핵심은 "예수 그리스도와 그가 십자가에 못 박히신 것"이었습니다. 십자가는 당시 사람들에게 수치와 저주의 상징이었지만, 바울은 이것이야말로 하나님의 지혜와 능력이 나타난 사건임을 선포했습니다. 세상의 지혜로는 도저히 이해할 수 없는 이 십자가의 도가 바로 하나님께서 만세 전부터 예비하신 구원의 지혜였습니다.\n\n이 하나님의 지혜는 성령을 통해서만 깨달을 수 있습니다. 바울은 하나님의 영이 하나님의 깊은 것까지도 통달하신다고 설명합니다. 마치 사람의 속마음을 그 사람의 영만이 아는 것처럼, 하나님의 일도 하나님의 영만이 아십니다. 그래서 성령을 받지 못한 육에 속한 사람은 하나님의 일을 어리석게 여기고 받아들이지 못합니다. 반면 성령을 받은 사람은 영적인 분별력을 갖게 되어 모든 것을 판단할 수 있게 됩니다.\n\n바울은 이 편지를 통해 고린도 교회가 인간의 지혜와 능력을 자랑하며 분파를 만드는 것이 얼마나 어리석은 일인지 깨우쳐 줍니다. 참된 지혜는 세상의 철학이나 수사학에 있지 않고, 십자가에 못 박히신 그리스도 안에 있습니다. 이 지혜를 깨닫는 것은 오직 성령의 조명하심으로만 가능하며, 이것이 바로 그리스도의 마음을 갖는 길입니다.', E'오늘의 핵심\n바울은 인간의 지혜가 아닌 성령의 능력으로 십자가의 복음을 전했으며, 이 하나님의 지혜는 오직 성령을 통해서만 깨달을 수 있음을 가르칩니다.\n\n묵상 질문\n1. 나는 신앙생활에서 인간적인 지혜와 능력을 의지하고 있지는 않나요?\n2. 십자가의 도가 내게는 어떤 의미로 다가오나요? 어리석음인가요, 하나님의 능력인가요?\n3. 성령의 조명하심을 구하며 말씀을 대하고 있나요? 오늘 하나님께서 내게 깨닫게 하시는 것은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-07-09', E'십자가의 도 (고린도전서 3장)', E'고린도전서 3장', E'바울은 고린도 교회의 성도들을 향해 안타까운 마음을 전합니다. 그들이 여전히 영적으로 어린아이와 같은 상태에 머물러 있기 때문입니다. 복음을 받은 지 시간이 흐렸음에도 불구하고 단단한 음식이 아닌 젖으로만 양육받아야 하는 상황이었습니다. 이는 그들 가운데 시기와 분쟁이 끊이지 않았기 때문입니다.\n\n고린도 교회는 "나는 바울에게" "나는 아볼로에게" 속한다고 주장하며 서로 편을 갈라 다투고 있었습니다. 바울은 이러한 분파주의가 육신에 속한 행동임을 분명히 지적합니다. 복음의 일꾼들을 우상화하고 서로 비교하며 경쟁하는 것은 하나님의 뜻이 아니었습니다. 바울과 아볼로는 모두 주님께서 세우신 사역자들일 뿐입니다. 한 사람은 씨를 뿌리고, 다른 사람은 물을 주었지만, 자라게 하시는 분은 오직 하나님이십니다.\n\n바울은 자신을 지혜로운 건축자로 비유하며 교회의 터를 닦았다고 말합니다. 그 터는 다름 아닌 예수 그리스도입니다. 이 터 위에 무엇을 세울 것인가는 각자의 책임입니다. 금이나 은, 보석으로 세울 수도 있고, 나무나 풀, 짚으로 세울 수도 있습니다. 그러나 마지막 날 불의 시험을 통과할 수 있는 것은 오직 견고한 재료로 세운 것뿐입니다.\n\n더 놀라운 선언이 이어집니다. "너희는 너희가 하나님의 성전인 것과 하나님의 성령이 너희 안에 계시는 것을 알지 못하느냐"(고전 3:16). 고린도 교회 성도들 자체가 하나님의 성전이라는 것입니다. 그러므로 분쟁과 다툼으로 교회를 어지럽히는 것은 곧 하나님의 성전을 더럽히는 일이 됩니다.\n\n바울은 세상의 지혜를 버리고 하나님의 지혜를 구하라고 권면합니다. 사람을 자랑하지 말고 오직 그리스도 안에서 하나 되라고 촉구합니다. 모든 것이 성도들의 것이며, 성도들은 그리스도의 것이고, 그리스도는 하나님의 것입니다. 이것이 하나님 나라의 질서입니다.', E'오늘의 핵심\n바울은 분파주의에 빠진 고린도 교회를 향해 오직 예수 그리스도라는 터 위에 서서 하나님의 성전된 공동체로서의 정체성을 회복하라고 권면합니다.\n\n묵상 질문\n1. 내가 신앙생활에서 사람을 따르고 의지하는 부분은 없는지 돌아보았나요?\n2. 하나님의 성전인 나와 교회 공동체를 거룩하게 지키기 위해 무엇을 버려야 할까요?\n3. 영적으로 성숙한 신앙인이 되기 위해 오늘 어떤 한 걸음을 내디디시겠습니까?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-07-10', E'십자가의 도 (고린도전서 4장)', E'고린도전서 4장', E'바울은 고린도 교회의 분열 문제를 다루면서 사역자의 진정한 정체성과 역할을 밝혀줍니다. 그는 자신과 아볼로를 "그리스도의 일꾼이요 하나님의 비밀을 맡은 자"(고전 4:1)로 규정하며, 사역자에게 가장 중요한 것은 충성임을 강조합니다. 당시 고린도 교회는 각자가 따르는 지도자를 내세우며 서로를 판단하고 정죄하는 일에 몰두하고 있었습니다. 이에 바울은 사람의 판단이 얼마나 제한적이고 불완전한지를 지적합니다. 심지어 자기 자신도 온전히 판단할 수 없으며, 오직 주님만이 진정한 심판자이심을 고백합니다.\n\n바울은 고린도 교인들의 영적 교만을 날카롭게 지적합니다. 그들은 마치 이미 완성된 신앙에 도달한 것처럼 행동하며, 배부르고 풍성하며 왕이 된 것처럼 자만하고 있었습니다. 이와 대조적으로 바울은 사도들의 현실적인 고난을 생생하게 묘사합니다. 주리고 목마르며 헐벗고 매맞으며 정처 없이 떠도는 삶, 손수 일하며 모욕과 박해를 받는 처지였습니다. 그러나 이러한 고난 속에서도 그들은 축복하고 참고 권면하는 삶을 살았습니다. 이것이 바로 십자가를 지신 그리스도를 따르는 참된 제자의 모습이었습니다.\n\n편지의 어조가 갑자기 부드러워지면서 바울은 자신을 영적 아버지로, 고린도 교인들을 사랑하는 자녀로 표현합니다. 그는 복음으로 그들을 낳았기에 아버지의 마음으로 권면하고 있음을 밝힙니다. 디모데를 보내는 것도 이러한 아버지의 사랑에서 비롯된 것이었습니다. 마지막으로 바울은 하나님의 나라가 말에 있지 않고 능력에 있음을 선포하며, 교만한 자들의 헛된 말이 아닌 진정한 영적 능력을 확인하겠다고 경고합니다. 사랑과 온유함으로 가기를 원하지만 필요하다면 엄한 징계도 불사하겠다는 아버지의 단호한 사랑이 담겨 있습니다.', E'오늘의 핵심\n바울은 참된 사역자는 하나님의 비밀을 맡은 충성된 일꾼이며, 하나님의 나라는 교만한 말이 아닌 겸손한 섬김의 능력으로 나타남을 가르칩니다.\n\n묵상 질문\n1. 나는 사람들의 평가와 인정에 얼마나 매여 있으며, 오직 주님의 판단만을 구하고 있나요?\n2. 영적으로 ''이미 배부르다''고 착각하며 교만해진 부분은 없는지 돌아보셨나요?\n3. 하나님 나라의 능력이 내 삶에서 어떻게 나타나기를 원하시나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-07-11', E'구원에 이르게 하는 통로 (고린도후서 1장)', E'고린도후서 1장', E'바울은 고린도 교회에 보낸 첫 번째 편지가 오히려 일부 성도들에게 오해와 비난을 불러일으켰다는 소식을 듣고 마음이 무거웠습니다. 그의 사도권을 의심하고 그의 진정성을 폄하하는 목소리들이 교회 안에 일어났던 것입니다. 이런 상황에서 바울은 고린도후서를 시작하며 먼저 "자비의 아버지시요 모든 위로의 하나님"(고후 1:3)을 찬송합니다. 그는 자신이 겪은 환난과 고통을 통해 깨달은 하나님의 위로하심을 고린도 성도들과 나누고자 했습니다.\n\n바울은 아시아에서 겪은 극심한 환난을 언급하며, 그 고통이 너무 심해 "살 소망까지 끊어지고" 사형 선고를 받은 것 같았다고 고백합니다. 그러나 이 모든 과정은 자기 자신을 의지하지 않고 "죽은 자를 다시 살리시는 하나님"만을 의지하게 하시려는 하나님의 섭리였음을 깨닫게 됩니다. 이처럼 그리스도인이 받는 고난은 단순한 불행이 아니라, 하나님의 위로를 경험하고 그 위로로 다른 이들을 위로할 수 있는 통로가 됩니다.\n\n한편 바울은 고린도 방문 계획을 변경한 것에 대해 변명하거나 핑계를 대지 않고, 오히려 그것이 고린도 성도들을 아끼는 마음에서 비롯되었음을 진솔하게 밝힙니다. 그는 자신의 말과 행동이 "예 하고 아니라 함이 없다"고 단언하며, 이는 그리스도 안에서 하나님의 모든 약속이 "예"가 되는 것과 같은 원리임을 설명합니다. 바울의 사역 원칙은 성도들의 믿음을 주관하려는 것이 아니라 그들의 기쁨을 돕는 것이었습니다.\n\n이렇게 바울은 오해와 비난 속에서도 사랑과 진실함으로 대화를 이어갑니다. 그의 모습은 환난 중에도 하나님의 위로를 붙잡고, 그 위로로 다시 형제자매를 위로하는 성숙한 그리스도인의 표본을 보여줍니다.', E'오늘의 핵심\n환난 중에 경험한 하나님의 위로는 고통당하는 다른 이들을 위로할 수 있는 능력이 되며, 그리스도인의 삶은 이러한 위로의 순환 가운데 성숙해집니다.\n\n묵상 질문\n1. 내가 겪은 고난과 아픔이 다른 사람을 위로하는 통로가 된 경험이 있나요?\n2. 오해받고 비난받을 때에도 사랑으로 대화를 이어가는 것이 왜 중요할까요?\n3. 하나님의 위로를 경험하기 위해 내가 내려놓아야 할 자기 의존은 무엇인가요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-07-12', E'구원에 이르게 하는 통로 (고린도후서 2장)', E'고린도후서 2장', E'바울이 고린도 교회에 보낸 첫 번째 편지는 예상치 못한 결과를 낳았습니다. 교회의 문제들을 해결하고자 했던 그의 진심 어린 권면이 오히려 일부 성도들에게 상처와 근심을 안겨준 것입니다. 이러한 상황에서 바울은 고린도 교회를 향한 자신의 마음을 다시 한 번 전하게 됩니다. 그는 "많은 눈물로" 편지를 썼다고 고백하며, 이것이 그들을 근심하게 하려는 것이 아니라 "넘치는 사랑"을 알게 하려 함이었다고 설명합니다.\n\n특별히 바울은 교회 안에서 벌어진 징계의 문제를 다룹니다. 죄를 범한 사람에게 내려진 벌이 이미 충분하므로, 이제는 그를 용서하고 위로해야 한다고 권면합니다. 지나친 징계로 인해 그가 "너무 많은 근심에 잠길까" 염려하는 바울의 모습에서 목회자의 세심한 배려가 드러납니다. 징계의 목적이 파멸이 아니라 회복에 있음을 분명히 하며, 사랑을 나타내라고 권하는 것입니다. 이는 사탄이 분열과 정죄를 통해 교회를 무너뜨리려는 계책을 간파한 영적 통찰에서 나온 권면이었습니다.\n\n바울은 드로아에서 복음의 문이 열렸음에도 디도를 만나지 못해 마음이 편치 않아 마게도냐로 떠났다고 전합니다. 이는 사역의 기회보다 고린도 교회의 소식을 듣는 것이 더 급했음을 보여줍니다. 그럼에도 불구하고 바울은 하나님께 감사를 드립니다. 하나님께서 "각처에서 그리스도를 아는 냄새를 나타내시는" 은혜를 주셨기 때문입니다. \n\n복음을 전하는 사역자들은 "그리스도의 향기"가 되어, 어떤 이들에게는 생명에 이르는 냄새가 되고 어떤 이들에게는 사망에 이르는 냄새가 됩니다. 동일한 복음이 듣는 사람의 반응에 따라 전혀 다른 결과를 낳는 것입니다. 이 막중한 책임 앞에서 바울은 "누가 이 일을 감당하리요"라고 탄식하면서도, 하나님의 말씀을 혼잡하게 하지 않고 순전함으로 전하겠다는 결단을 보여줍니다. 고린도 교회와의 갈등 속에서도 복음 사역자의 정체성을 잃지 않는 바울의 모습이 우리에게 깊은 도전을 줍니다.', E'오늘의 핵심\n사랑으로 권면했던 말이 상처가 될 수 있지만, 그리스도인은 용서와 회복의 사역을 통해 그리스도의 향기를 전파하는 사명을 감당해야 합니다.\n\n묵상 질문\n1. 내가 선한 의도로 한 말이나 행동이 누군가에게 상처가 된 경험이 있나요?\n2. 징계와 용서 사이에서 균형을 잡는 것이 왜 중요할까요?\n3. 나는 주변 사람들에게 생명의 향기가 되고 있나요, 아니면 사망의 냄새가 되고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-07-13', E'구원에 이르게 하는 통로 (고린도후서 3장)', E'고린도후서 3장', E'바울은 자신의 사도직을 의심하는 고린도 교인들에게 놀라운 진리를 전합니다. 추천서가 필요하다는 그들의 비난에 대해, 바울은 고린도 교인들 자신이 바로 살아있는 편지라고 선언합니다. 먹으로 쓴 것이 아니라 살아계신 하나님의 영으로, 돌판이 아닌 마음판에 쓰인 그리스도의 편지라는 것입니다. 이는 단순한 비유가 아니라 새 언약의 본질을 보여주는 깊은 신학적 통찰입니다.\n\n바울은 구약의 율법과 새 언약을 대조하며 복음의 우월성을 설명합니다. 모세가 시내산에서 받은 율법도 영광스러웠지만, 그것은 돌판에 새겨진 문자로서 정죄하고 죽이는 직분이었습니다. 반면 성령으로 말미암은 새 언약의 직분은 의롭다 하시고 살리는 직분입니다. 모세의 얼굴에 나타났던 영광이 점차 사라지는 것이었다면, 그리스도 안에서 주어진 영광은 영원히 계속되는 것입니다.\n\n특별히 주목할 것은 수건의 비유입니다. 모세가 자신의 얼굴을 수건으로 가렸듯이, 지금도 많은 유대인들이 구약을 읽을 때 그들의 마음에 수건이 덮여 있어 진리를 깨닫지 못한다고 바울은 지적합니다. 그러나 "언제든지 주께로 돌아가면 그 수건이 벗겨지리라"(고후 3:16)는 약속이 있습니다. 이는 그리스도 안에서만 구약의 참된 의미가 밝히 드러난다는 뜻입니다.\n\n바울은 마지막으로 그리스도인의 변화에 대한 놀라운 비전을 제시합니다. 수건을 벗은 얼굴로 주의 영광을 바라보는 우리는 그리스도의 형상으로 점점 변화되어 간다는 것입니다. 이는 단순히 도덕적 개선이 아니라 주의 영으로 말미암은 근본적인 변화입니다. 율법의 문자가 아닌 성령의 자유함 가운데서, 우리는 영광에서 영광으로 나아가는 변화의 여정을 걷게 됩니다.', E'오늘의 핵심\n성령으로 쓰여진 살아있는 편지인 그리스도인들은 율법의 정죄가 아닌 복음의 자유 가운데서 그리스도의 형상으로 변화되어 갑니다.\n\n묵상 질문\n1. 나는 다른 사람들에게 읽혀지는 그리스도의 편지로서 어떤 메시지를 전하고 있나요?\n2. 내 마음에 여전히 벗겨지지 않은 수건이 있어 하나님의 진리를 온전히 보지 못하는 부분이 있나요?\n3. 영광에서 영광으로 변화되어 가는 과정에서 성령님의 역사를 어떻게 경험하고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-07-14', E'그리스도인의 구별된 삶 (고린도후서 5장)', E'고린도후서 5장', E'바울은 고린도 교회에 깊은 영적 진리를 전하면서 현재의 고난을 넘어 영원한 소망을 바라보도록 권면합니다. 그는 우리의 육체를 "땅에 있는 장막 집"으로, 부활의 몸을 "하늘에 있는 영원한 집"으로 비유하면서 신자들이 가져야 할 궁극적인 소망을 제시합니다. 이 땅에서의 삶이 아무리 힘들고 어려워도, 하나님께서 예비하신 영원한 처소가 있다는 확신이 바로 그리스도인의 담대함의 근거가 됩니다.\n\n바울은 이러한 확신 가운데서도 현재의 삶에 충실할 것을 강조합니다. "그런즉 우리는 몸으로 있든지 떠나든지 주를 기쁘시게 하는 자가 되기를 힘쓰노라"(고후 5:9)는 그의 고백은, 영원을 바라보면서도 오늘 이 자리에서 최선을 다하는 신앙의 균형을 보여줍니다. 하나님께서 성령을 보증으로 주셨다는 확신은 우리로 하여금 보이지 않는 것을 믿음으로 바라보며 살아갈 수 있게 합니다.\n\n특별히 바울은 그리스도의 대속 사역을 통해 일어난 근본적인 변화를 강조합니다. 그리스도의 죽으심과 부활은 단순히 개인의 구원에 그치지 않고, 하나님과 세상을 화목케 하는 우주적 사건입니다. 이 화목의 은혜를 받은 자들은 이제 화목하게 하는 직분을 받은 사신이 되어, 하나님의 화목 메시지를 세상에 전하는 사명을 감당하게 됩니다. 바울은 이것이 바로 새로운 피조물이 된 자들의 정체성이며 사명임을 분명히 합니다.', E'오늘의 핵심\n그리스도 안에서 새로운 피조물이 된 우리는 영원한 소망을 품고 살면서도 현재의 삶에서 화목의 사신으로 부름받았습니다.\n\n묵상 질문\n1. 영원한 집에 대한 소망이 오늘의 어려움을 이겨내는 힘이 되고 있나요?\n2. 내가 그리스도 안에서 새로운 피조물이 되었다는 것을 어떻게 경험하고 있나요?\n3. 화목하게 하는 직분을 받은 자로서 나는 어떤 관계들을 회복시켜야 할까요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-07-16', E'그리스도인의 구별된 삶 (고린도후서 6장)', E'고린도후서 6장', E'바울은 고린도 교회를 향해 "하나님의 은혜를 헛되이 받지 말라"고 권면하며 6장을 시작합니다. 이사야의 예언을 인용하면서 "지금은 은혜 받을 만한 때요 보라 지금은 구원의 날"임을 강조합니다. 구원의 때가 도래했다는 이 선포는 그리스도 안에서 성취된 화목의 복음을 받아들여야 할 긴급성을 담고 있습니다.\n\n바울은 자신의 사역이 비방받지 않도록 극도로 조심하면서도, 동시에 복음 사역자가 겪는 고난의 목록을 상세히 제시합니다. 환난과 궁핍, 매 맞음과 갇힘, 그리고 육체적 고통까지 나열하면서도, 이 모든 것을 "하나님의 일꾼"으로서 견디어 낸다고 고백합니다. 여기서 주목할 것은 바울이 고난 자체를 자랑하는 것이 아니라, 그 고난 속에서도 지켜낸 "깨끗함과 지식과 오래 참음과 자비함과 성령의 감화와 거짓이 없는 사랑"을 증거하고 있다는 점입니다.\n\n특히 8절부터 10절에 나타난 역설적 표현들은 복음 사역자의 실존을 깊이 있게 보여줍니다. "속이는 자 같으나 참되고", "죽은 자 같으나 살아 있고", "가난한 자 같으나 많은 사람을 부요하게 하는" 이 모순적 진술들은 세상의 가치관과 하나님 나라의 가치관이 얼마나 다른지를 극명하게 드러냅니다. 바울의 사역은 세상의 눈으로는 실패처럼 보이지만, 하나님의 관점에서는 놀라운 열매를 맺고 있었던 것입니다.\n\n본문 후반부에서 바울은 고린도 교회를 향한 자신의 열린 마음을 토로하면서, 동시에 신자와 불신자 간의 구별된 삶을 강조합니다. "믿지 않는 자와 멍에를 함께 메지 말라"는 권면은 단순히 사회적 단절을 의미하는 것이 아니라, 신앙의 정체성을 분명히 하라는 요청입니다. 우리가 "살아 계신 하나님의 성전"이라는 놀라운 선언과 함께, 하나님께서 우리 가운데 거하시며 우리의 아버지가 되신다는 약속으로 마무리되는 이 장은, 구별된 삶으로의 부르심과 그에 따른 하나님의 친밀한 임재를 동시에 제시합니다.', E'오늘의 핵심\n복음 사역자의 삶은 세상의 기준으로는 모순적이지만, 그 역설적 삶 속에서 하나님의 능력이 온전히 드러나며, 이를 통해 우리는 거룩한 하나님의 백성으로 구별된 정체성을 갖게 됩니다.\n\n묵상 질문\n1. 내가 받은 하나님의 은혜를 헛되이 하지 않으려면 어떻게 살아야 할까요?\n2. 바울처럼 고난 속에서도 성령의 감화와 거짓 없는 사랑을 유지할 수 있는 비결은 무엇일까요?\n3. "하나님의 성전"으로서 나는 세상과 어떻게 구별된 삶을 살고 있나요?');
INSERT INTO public.qt_plans (date, title, reference, text, commentary) VALUES ('2029-07-17', E'그리스도인의 구별된 삶 (고린도후서 7장)', E'고린도후서 7장', E'바울은 고린도 교회에 보낸 이전 편지가 그들에게 근심을 끼친 것을 알고 있었습니다. 그 편지는 교회 내의 문제들을 직설적으로 지적하며 책망하는 내용이었기에, 바울 자신도 한때는 그렇게 쓴 것을 후회하기도 했습니다. 그러나 디도를 통해 전해 들은 소식은 바울의 마음을 기쁨으로 가득 채워주었습니다. 고린도 교회가 그 책망의 편지를 받고 근심했지만, 그것이 단순한 상처나 실망으로 끝나지 않고 진정한 회개로 이어졌다는 것입니다.\n\n"하나님의 뜻대로 하는 근심은 후회할 것이 없는 구원에 이르게 하는 회개를 이루는 것이요 세상 근심은 사망을 이루는 것이니라"(고후 7:10). 이 말씀을 통해 바울은 근심에도 두 종류가 있음을 분명히 보여줍니다. 세상적인 근심은 단지 들통 났다는 수치심이나 처벌에 대한 두려움에서 비롯되며 결국 영적인 죽음으로 이끌어갑니다. 그러나 하나님의 뜻대로 하는 근심은 자신의 죄를 진정으로 깨닫고 돌이키는 회개의 열매를 맺게 합니다.\n\n고린도 교회의 반응은 바로 이러한 거룩한 근심의 모범을 보여주었습니다. 그들은 간절함으로 자신들을 변호하고, 잘못에 대한 의로운 분노를 품었으며, 하나님을 두려워하는 마음으로 죄를 처리했습니다. 이 모든 과정을 통해 그들은 스스로의 깨끗함을 증명했고, 바울과의 관계도 회복되었습니다.\n\n특별히 주목할 점은 바울이 디도의 방문을 통해 받은 위로입니다. 마게도냐에서 육체적으로나 정신적으로 극심한 환난을 겪고 있던 바울에게, 고린도 교회의 회개와 사랑의 소식을 전한 디도의 방문은 하나님께서 주시는 특별한 위로였습니다. 바울은 이를 통해 "낙심한 자들을 위로하시는 하나님"의 손길을 경험했습니다. 목회자와 성도 사이의 이러한 상호 신뢰와 사랑의 관계야말로 교회 공동체가 추구해야 할 아름다운 모습입니다.', E'오늘의 핵심\n하나님의 뜻대로 하는 근심은 참된 회개를 낳고, 그 회개는 목회자와 성도 사이에 더 깊은 신뢰와 사랑의 관계를 맺게 합니다.\n\n묵상 질문\n1. 내가 경험한 근심은 세상적 근심인가요, 아니면 하나님의 뜻대로 하는 거룩한 근심인가요?\n2. 사랑하는 사람의 책망을 받을 때, 나는 어떤 마음과 자세로 반응하고 있나요?\n3. 고린도 교회처럼 회개를 통해 관계가 더욱 깊어진 경험이 있다면 나누어 보실래요?');
